INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2h_L3_B', 'G2h', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a map of a classroom. The door is at the top. The teacher''s desk is at the bottom. The instructions say ''Walk straight out the door to get to the teacher''s desk.'' Is this right?', 'Notices the map is oriented differently than the instructions assume, or the starting point is confused.', 'Agrees with the instructions blindly.', 'When you hold a map, why does it help to turn the map so it matches the room?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2h_L3_C', 'G2h', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend gave coordinates for the hidden toy as ''B''. Why can''t I find it?''', 'Explains that ''B'' is a whole column, so you need a number to know which specific square in column B.', 'Looks in square B1 by default.', 'How many different squares are in column B?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2h_L4_A', 'G2h', 4, 'A', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Draw a map of your bedroom. Include a grid (like A, B, C and 1, 2, 3) over it. Tell me the coordinates of your bed.''', 'Creates a functional map with a coordinate system and accurately locates an object.', 'Draws a picture without top-down perspective or forgets the grid.', 'If you moved your bed to the other side of the room, what would the new coordinates be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2h_L4_B', 'G2h', 4, 'B', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Hide a toy somewhere in the house. Write down 3 directional clues (using left, right, forward, or North/South) for me to find it.''', 'Generates clear, sequential, and accurate spatial instructions from a fixed starting point.', 'Uses relative/unhelpful clues (''it''s near the couch'').', 'Why is it important to tell me exactly where to start before I read your clues?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2h_L4_C', 'G2h', 4, 'C', 'Design', NULL, NULL, NULL, NULL, NULL, 'Say: ''Invent a new compass. Instead of North, South, East, West, use 4 landmarks around our house/school (like ''Towards the road'', ''Towards the big tree''). Draw it.''', 'Creates a localized orientation system based on stable landmarks.', 'Uses things that move (like ''towards the car'').', 'Why do real compasses use magnetic North instead of landmarks like trees?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2h_L4_M', 'G2h', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'A stranger asks you how to get to the hospital. You tell them ''Go straight, then turn left.'' They get lost. What important information did you forget to tell them?', 'Child realizes the instructions lack a distance/landmark (e.g., ''go straight for 2 blocks'' or ''turn left at the big tree'').', 'Cannot identify the missing information.', 'How do they know WHEN to turn left?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

