INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_A', 'M2', 1, 'A', 'Physical modeling', '24 small objects (e.g., beans or blocks)', NULL, NULL, NULL, NULL, 'Say: ''We are planting a small garden. Make 3 rows, and put 4 plants in each row. How many plants did we use in total?''', 'Child arranges objects into a 3x4 array and correctly counts 12 total.', 'Child makes uneven rows, random groups, or miscounts.', 'How does arranging them in rows make it easier to count them all?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_B', 'M2', 1, 'B', 'Physical modeling', 'A box or outline on paper, Small square tiles or blocks', NULL, NULL, NULL, NULL, 'Say: ''This box is the floor of a new room. We are laying square tiles. Put 5 tiles in a row along one wall, and keep making rows until you have 4 rows. How many tiles cover the floor?''', 'Child creates a 4x5 array inside the boundary and counts 20 total tiles.', 'Child places tiles randomly without rows, or miscounts the total.', 'If we took away one entire row, how many tiles would be left?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L1_C', 'M2', 1, 'C', 'Physical modeling', 'Paper, Pencil, 15 small objects', NULL, NULL, NULL, NULL, 'Say: ''We have 15 books. We want to put them on shelves so that every shelf has exactly 5 books. Make the piles, then draw a picture of the shelves.''', 'Child makes 3 equal piles of 5, then draws a representation showing 3 shelves with 5 items each.', 'Child makes unequal piles, or draws a picture that doesn''t match the physical model.', 'How did you know you needed exactly 3 shelves?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_A', 'M2', 2, 'A', 'Structured translation', NULL, NULL, NULL, NULL, NULL, 'Say: ''A baker has 4 trays of cookies. Each tray holds 6 cookies. Draw a picture of the trays, then write a math sentence (equation) that shows how to find the total number of cookies.''', 'Child draws 4 groups of 6 and writes ''4 x 6 = 24'' or ''6 + 6 + 6 + 6 = 24''.', 'Child writes the wrong numbers, adds 4 and 6 to get 10, or draws an incorrect picture.', 'Why did you use the number 6 four times in your model?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_B', 'M2', 2, 'B', 'Structured translation', NULL, NULL, NULL, NULL, NULL, 'Say: ''We are building a fence. The yard is shaped like a rectangle. It is 5 steps long and 3 steps wide. Draw the yard and write an equation to show how many steps of fence we need to go all the way around.''', 'Child draws a rectangle, labels the sides (5, 3, 5, 3), and writes an equation like ''5 + 3 + 5 + 3 = 16''.', 'Child only adds 5 + 3 = 8, forgetting the other two sides.', 'Why are there four numbers in your addition sentence instead of just two?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L2_C', 'M2', 2, 'C', 'Structured translation', NULL, NULL, NULL, NULL, NULL, 'Say: ''I asked 5 friends what their favorite color is. 3 said Red, 2 said Blue. Draw a bar graph to show this data, then write a math sentence showing the total number of friends I asked.''', 'Child draws a bar graph with ''Red'' at 3 and ''Blue'' at 2, and writes ''3 + 2 = 5''.', 'Child draws the graph incorrectly (e.g., no labels, wrong heights) or writes an incorrect equation.', 'How does your graph show the same information as your math sentence?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_A', 'M2', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''A word problem says: There are 5 cars. Each car has 4 wheels. My friend drew 5 circles and 4 circles, and wrote 5 + 4 = 9 wheels. What is wrong with their model?''', 'Child explains that the friend added cars and wheels together, instead of putting 4 wheels ON EACH of the 5 cars.', 'Child thinks the math is correct because 5 + 4 is 9.', 'How should the drawing look to correctly show wheels on cars?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_B', 'M2', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''The problem is to find the perimeter of a rectangular field that is 6 meters long and 2 meters wide. My friend wrote 6 + 2 = 8 meters. What part of the real world did they forget?''', 'Child identifies that a rectangle has four sides, and the friend only accounted for two of them.', 'Child agrees with the friend''s answer.', 'If you only build 8 meters of fence, what will the field look like?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L3_C', 'M2', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''My friend collected data on favorite pets. They tallied 4 Dogs, 3 Cats, and 2 Fish. To find the total, they multiplied 4 x 3 x 2. Why does their math model not fit the real world?''', 'Child explains that to find a total number of different things combined, you must add, not multiply.', 'Child thinks multiplying is just another way to get a big total.', 'If you actually multiply 4 x 3 x 2, you get 24. Do you have 24 pets here?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_A', 'M2', 4, 'A', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Invent a word problem about our house that requires multiplication to solve it. Tell me the problem, draw a picture to model it, and write the math equation.''', 'Child creates a valid scenario involving equal groups (e.g., ''There are 3 windows, and each has 2 curtains''), models it accurately, and writes the correct equation.', 'Child creates an addition problem (e.g., ''3 windows and 2 doors''), or the model/equation doesn''t match the story.', 'How do you know for sure your story requires multiplication and not just addition?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_B', 'M2', 4, 'B', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''I will give you an equation: 4 + 4 + 4 + 4 = 16. Write a short story about building something that uses this equation. Then draw a diagram of what you built.''', 'Child invents a story involving four sides of equal length (like a square fence) or four groups of four items, and draws a matching model.', 'Child just writes an abstract story (''I had 4 numbers and added them'') without a real-world object or diagram.', 'If you changed your story to be about a triangle, what would the equation look like?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_C', 'M2', 4, 'C', 'Design and Justification', NULL, NULL, NULL, NULL, NULL, 'Say: ''Design a simple map of a small park with a path running through it. Write down a set of instructions using steps and directions (left/right) so someone can walk the path. Then, write an equation to show how many total steps long the path is.''', 'Child draws a map, writes clear directional instructions (e.g., ''Walk 10 steps, turn right, walk 5 steps''), and provides the correct total sum.', 'Child''s instructions don''t match the map, or the equation is missing/incorrect.', 'If I walked the path backwards, would the total number of steps be the same? Why?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('M2_L4_M', 'M2', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We need to buy new tiles to cover the bathroom floor completely. We don''t want to buy too many, and we don''t want to run out. What exactly do you need to do to figure out how many tiles to buy?', 'Child describes a process of modeling the area: counting how many tiles fit along the length and width, and multiplying them (or drawing a grid to count the total).', 'Child suggests guessing, or just measuring one side.', 'If you know the floor is 6 tiles long and 5 tiles wide, why do you multiply them instead of adding 6 and 5?', '{"default":{"objects":["blocks","tiles","cards"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["stones","bottle caps","sticks"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

-- File: english_band_2_strand_1.json
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L1_A', 'ENG_PS2a', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'I am going to say three words. Two words have the same middle sound, but one is different. Listen: ''bat'', ''cat'', ''bit''. Which word sounds different in the middle?', 'Child correctly identifies ''bit''.', 'If wrong, stretch the words: ''b-aaaa-t'', ''c-aaaa-t'', ''b-iiii-t''. Ask them to try again.', 'What sound did you hear in the middle of ''bat''? What about ''bit''?', '{"default":{"words":[["bat","cat","bit"],["hop","mop","cup"],["sit","fit","set"]]},"ug":{"words":[["pan","fan","pin"],["pot","hot","hut"],["tin","bin","ten"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L1_B', 'ENG_PS2a', 1, 'B', 'Physical Sorting', '5 small containers or drawn circles, Small objects or drawn pictures representing short vowel CVC words (e.g., pen, pin, pot, pan, cup)', NULL, NULL, NULL, NULL, 'We have 5 boxes, one for each short vowel sound: /a/, /e/, /i/, /o/, /u/. Pick up an object, say its name, and put it in the box with the matching middle sound.', 'Child sorts the objects into the correct vowel categories.', 'If wrong, ask them to say the word slowly and isolate the middle sound.', 'Why did you put the ''pen'' in that box? What sound is in the middle?', '{"default":{"objects":["pen","pin","pot","pan","cup"]},"ug":{"objects":["tin","pot","pan","cup","bed"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L1_C', 'ENG_PS2a', 1, 'C', 'Verbal Substitution', 'None', NULL, NULL, NULL, NULL, 'Say the word ''mat''. Now, change the /a/ sound in the middle to an /o/ sound. What is the new word?', 'Child successfully produces the new word (''mot'' or similar, depending on prompt). Focus is on sound manipulation, not real words necessarily.', 'If incorrect, say the sounds individually: /m/ /a/ /t/, now /m/ /o/ /t/. Blend them for the child.', 'How did the word change when we swapped the middle sound?', '{"default":{"prompts":[["mat","/o/","mot"],["sit","/e/","set"]]},"ug":{"prompts":[["pan","/i/","pin"],["pot","/u/","put"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L2_A', 'ENG_PS2a', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will say a word. You will say the sounds you hear, and then write the letters. The word is ''dog''.', 'Child says /d/ /o/ /g/ and writes ''dog''.', 'If spelled wrong, point to the incorrect letter and ask: ''What sound does this letter make? Does that match the word we want?''', 'How did you know which vowel to use in the middle?', '{"default":{"words":["dog","cat","pig","sun","hen"]},"ug":{"words":["cat","dog","pig","sun","hen"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L2_B', 'ENG_PS2a', 2, 'B', 'Oral->Written Word Building', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Let''s build a word ladder. Start by writing the word ''sit''. Read it aloud. Now change one letter to make it say ''sat''. Say the word, then write it.', 'Child writes ''sit'', says ''sat'', then writes ''sat''.', 'If they change the wrong letter, have them point to each letter and sound out what they wrote.', 'Which part of the word did you change? Why?', '{"default":{"ladders":[["sit","sat","mat","map"],["pin","pan","pat","pot"]]},"ug":{"ladders":[["pin","pan","pat","pot"],["tin","tan","tap","top"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L2_C', 'ENG_PS2a', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will read a short sentence. Repeat it back to me, then write it down. ''The big pig sat in the mud.''', 'Child repeats the sentence correctly and writes it with mostly accurate phonetic spelling for CVC words.', 'If they miss words, repeat the sentence. If CVC words are misspelled, guide them to sound it out.', 'Read the sentence back to me. Did you include all the words?', '{"default":{"sentences":["The big pig sat in the mud.","A red bug is on the rug."]},"ug":{"sentences":["The big pig sat in the mud.","A red bug is on the mat."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L3_A', 'ENG_PS2a', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Look at this sentence: ''The c-o-t ran after the mouse.'' There is a spelling mistake that changes the meaning. Find the mistake and fix it.', 'Child identifies ''cot'' as incorrect and changes it to ''cat''.', 'If they can''t find it, ask them to read the sentence aloud exactly as it is written.', 'Why doesn''t ''cot'' make sense in this sentence? What is the correct word?', '{"default":{"sentences":[{"text":"The c-o-t ran after the mouse.","error":"cot","fix":"cat"}]},"ug":{"sentences":[{"text":"The c-o-t ran after the rat.","error":"cot","fix":"cat"}]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L3_B', 'ENG_PS2a', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a sentence, but I will make a mistake with one of the words. Listen: ''I used a p-e-n to hold the papers together.'' Did I say that right?', 'Child identifies that ''pen'' is the wrong word and suggests ''pin''.', 'If they miss it, repeat the sentence emphasizing the incorrect word.', 'What does a ''pen'' do? What did I actually need?', '{"default":{"sentences":[{"text":"I used a p-e-n to hold the papers together.","error":"pen","fix":"pin"}]},"ug":{"sentences":[{"text":"I used a p-e-n to hold the cloth together.","error":"pen","fix":"pin"}]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L3_C', 'ENG_PS2a', 3, 'C', 'Nonsense Word Reading', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here is a list of words. Some are real words, and some are nonsense (silly) words. Read each one and tell me if it is real or nonsense: ''bim'', ''cat'', ''zug'', ''mop''.', 'Child correctly reads the words and categorizes them.', 'If they misread a word, ask them to point to each letter and say the sound, then blend.', 'How do you know ''zug'' isn''t a real word?', '{"default":{"words":["bim","cat","zug","mop"]},"ug":{"words":["bim","cat","zug","mop"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_A', 'ENG_PS2a', 4, 'A', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Imagine you are teaching a younger child what a ''short a'' sound is. Explain it to them, and write down three example words to show them.', 'Child can articulate the sound and provides three accurate CVC words with short ''a''.', 'If they struggle to explain, ask them to make the sound first, then think of words that have it in the middle.', 'Why did you choose those three words to show the short ''a'' sound?', '{"default":{"target_vowel":"short a"},"ug":{"target_vowel":"short a"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_B', 'ENG_PS2a', 4, 'B', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the silliest sentence you can using as many short ''i'' CVC words as possible. Say the sentence out loud before you write it.', 'Child orally composes and then writes a sentence containing multiple short ''i'' words.', 'If they struggle, provide a starting word like ''The pig...''', 'Read your sentence to me. Which words have the short ''i'' sound?', '{"default":{"target_vowel":"short i"},"ug":{"target_vowel":"short i"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_C', 'ENG_PS2a', 4, 'C', 'Categorisation & Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Create two lists. At the top of one, write ''-at''. At the top of the other, write ''-in''. Now, write down as many words as you can think of that fit into these two families.', 'Child successfully generates at least 3-4 words for each word family.', 'If they get stuck, offer a starting sound: ''What if we put a /p/ sound in front of -at?''', 'What do all the words in the ''-at'' list have in common?', '{"default":{"families":["-at","-in"]},"ug":{"families":["-at","-in"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2a_L4_M', 'ENG_PS2a', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We are going to write a short shopping list. I need a pen, a pan, and a mop. Say the items back to me, and then write the list.', 'Child accurately repeats the items and spells ''pen'', ''pan'', and ''mop'' correctly on the list.', 'Do not correct them during the task. If failed, return to Execute level tasks focusing on those specific vowel sounds.', 'Read your list back to me to make sure we have everything.', '{"default":{"list":["pen","pan","mop"]},"ug":{"list":["tin","pan","cup"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L1_A', 'ENG_PS2b', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to the start of these two words: ''stop'' and ''sop''. In one of these words, I hear two consonant sounds pushed together at the beginning. Which word is it?', 'Child identifies ''stop'' and can isolate the /s/ and /t/ sounds.', 'If incorrect, exaggerate the sounds: /s/-/t/-op vs /s/-op.', 'What two sounds did you hear at the start of ''stop''?', '{"default":{"word_pairs":[["stop","sop"],["play","pay"],["fast","fat"]]},"ug":{"word_pairs":[["stop","sop"],["play","pay"],["fast","fat"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L1_B', 'ENG_PS2b', 1, 'B', 'Physical Manipulation', 'Two small objects (like stones or beads)', NULL, NULL, NULL, NULL, 'Place the two stones far apart. Say /s/ for one stone, and /p/ for the other. Now push the stones together quickly and say the sounds together: /sp/. What word starts with /sp/?', 'Child successfully blends the sounds and suggests a word like ''spot'' or ''spin''.', 'If they struggle, guide their hands to push the stones while you say the sounds with them.', 'How is /sp/ different from just /s/ or /p/?', '{"default":{"blends":["sp","cl","tr"]},"ug":{"blends":["sp","cl","tr"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L1_C', 'ENG_PS2b', 1, 'C', 'Verbal Identification', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a word slowly: /f/ /l/ /a/ /g/. Can you push those sounds together and tell me the word?', 'Child says ''flag''.', 'If incorrect, say it a bit faster: /fl/ /ag/.', 'What two sounds do you hear at the very beginning of the word?', '{"default":{"words":["flag","crab","jump"]},"ug":{"words":["flag","crab","jump"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L2_A', 'ENG_PS2b', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will say a word. You say the sounds, and then write it. The word is ''frog''. Make sure you hear all the sounds at the beginning.', 'Child says /f/ /r/ /o/ /g/ and writes ''frog''.', 'If they write ''fog'', ask: ''Read what you wrote. Does that say frog or fog?''', 'What two letters are making the beginning sounds?', '{"default":{"words":["frog","slip","tent"]},"ug":{"words":["frog","slip","tent"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L2_B', 'ENG_PS2b', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''lap''. Say it aloud. Now, put a ''c'' sound at the beginning. Say the new word, then write it.', 'Child writes ''lap'', says ''clap'', and writes ''clap''.', 'If incorrect, segment the sounds for them: /c/ /l/ /a/ /p/.', 'What happened to the word when we added the ''c''?', '{"default":{"transformations":[["lap","clap"],["pot","spot"]]},"ug":{"transformations":[["lap","clap"],["pot","spot"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L2_C', 'ENG_PS2b', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Repeat this sentence, then write it: ''The frog sat on the log.''', 'Child repeats and accurately spells ''frog'' including the blend.', 'If ''frog'' is misspelled, focus just on that word and have them stretch out the sounds.', 'Read the sentence. Does the word start with an ''f'' sound and an ''r'' sound?', '{"default":{"sentences":["The frog sat on the log.","The crab ran fast."]},"ug":{"sentences":["The frog sat on the log.","The crab ran fast."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L3_A', 'ENG_PS2b', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Look at this sentence: ''I have a red s-l-e-d for the snow.'' Wait, that''s not right. It should say ''I have a red s-e-d for the snow.'' Or should it? Which word is correct?', 'Child identifies ''sled'' as the correct word.', 'If unsure, have them read both ''sled'' and ''sed'' and see which makes sense.', 'Why do we need the ''l'' in sled?', '{"default":{"words":["sled","sed"]},"ug":{"words":["drum","dum"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L3_B', 'ENG_PS2b', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''The baby will c-r-e-e-p on the floor.'' Now listen to this one: ''The baby will c-e-e-p on the floor.'' Which one sounds right?', 'Child identifies ''creep''.', 'If they miss the blend, repeat both words emphasizing the /r/.', 'What sound was missing in the second word?', '{"default":{"sentences":["The baby will creep on the floor.","The baby will ceep on the floor."]},"ug":{"sentences":["The baby will creep on the mat.","The baby will ceep on the mat."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L3_C', 'ENG_PS2b', 3, 'C', 'Fill in the blank', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here is a word with a blank at the beginning: ''__op''. Should we put ''st'', ''fl'', or ''cr'' at the beginning to make it the word for what you do at a red light?', 'Child selects ''st'' to make ''stop''.', 'If they guess wrong, sound out the incorrect options with them: ''fl-op? cr-op?''', 'Why wouldn''t ''flop'' work for a red light?', '{"default":{"target":"stop","options":["st","fl","cr"],"clue":"red light"},"ug":{"target":"stop","options":["st","fl","cr"],"clue":"red light"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_A', 'ENG_PS2b', 4, 'A', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the blend ''pl'' at the top of your paper. Say the sound out loud. Now, write three real words that start with that blend.', 'Child accurately generates and writes three words starting with ''pl'' (e.g., play, plum, plan).', 'If they write words that just start with ''p'', remind them to make the /p/ /l/ sound together.', 'Read your words. Do they all start with the same two sounds?', '{"default":{"blend":"pl"},"ug":{"blend":"pl"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_B', 'ENG_PS2b', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of an animal whose name starts with a blend, like a frog or a crab. Tell me a sentence about what that animal is doing, and then write it down.', 'Child orally composes and writes a sentence featuring an animal name with an initial blend.', 'If they choose an animal without a blend (like ''dog''), redirect them: ''Dog starts with one consonant sound. Can you think of one with two, like sn-ake?''', 'Which word in your sentence has a consonant blend?', '{"default":{"theme":"animals with blends"},"ug":{"theme":"animals with blends"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_C', 'ENG_PS2b', 4, 'C', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to me the difference between the word ''tap'' and the word ''trap''. What extra sound did we add, and where is it?', 'Child clearly explains that the /r/ sound was added after the /t/.', 'If they can''t explain, ask them to write both words and circle the difference.', 'How does adding that one letter change the meaning of the word?', '{"default":{"word_pair":["tap","trap"]},"ug":{"word_pair":["tap","trap"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2b_L4_M', 'ENG_PS2b', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Look around the room or outside. Tell me one thing you see that has a consonant blend in its name (like a plant, a step, or the sky). Say it in a sentence, and then write the sentence.', 'Child successfully identifies an object with a blend, composes a sentence orally, and writes it accurately.', 'Do not correct during the task. If they fail to identify a blend or spell it correctly, review Execute level tasks.', 'Show me the word in your sentence that has the blend. What two sounds are pushed together?', '{"default":{"prompt":"Look around the room or outside."},"ug":{"prompt":"Look around the room or outside."}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L1_A', 'ENG_PS2c', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to these words: ''ship'', ''shoe'', ''sun''. Two of these words start with a special sound made by two letters working together to make one new sound: /sh/. Which word does NOT start with the /sh/ sound?', 'Child identifies ''sun''.', 'If incorrect, emphasize the initial sounds: /sh/-ip, /sh/-oe, /s/-un.', 'What sound did ''sun'' start with? How is it different from the other two?', '{"default":{"words":["ship","shoe","sun"]},"ug":{"words":["shop","shoe","sun"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L1_B', 'ENG_PS2c', 1, 'B', 'Physical Manipulation', 'Letter tiles or cards: c, s, h, t', NULL, NULL, NULL, NULL, 'Put the ''s'' tile and the ''h'' tile together. When they stand next to each other, they don''t say /s/ /h/ anymore. They make a totally new sound: /sh/ (like telling someone to be quiet). Now put ''c'' and ''h'' together. They say /ch/ (like a train). Pick up the tiles that make the /sh/ sound.', 'Child selects ''sh''.', 'If wrong, repeat the sound association (quiet vs train).', 'Why do these two letters make only one sound now?', '{"default":{"digraphs":["sh","ch"]},"ug":{"digraphs":["sh","ch"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L1_C', 'ENG_PS2c', 1, 'C', 'Verbal Identification', 'None', NULL, NULL, NULL, NULL, 'I will say a word. If it starts with the /ch/ sound, say ''choo choo!''. If it doesn''t, just shake your head. Ready? ''Chip''.', 'Child responds appropriately (''choo choo!'').', 'If they miss it, exaggerate the /ch/ sound.', 'What sound did you hear at the beginning of ''chip''?', '{"default":{"words":[["chip",true],["cat",false],["chop",true]]},"ug":{"words":[["chop",true],["cup",false],["chin",true]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L2_A', 'ENG_PS2c', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a word. You say the sounds, and then write the letters. Remember, some sounds need two letters! The word is ''shop''.', 'Child says /sh/ /o/ /p/ and writes ''shop''.', 'If they write ''sop'', ask: ''Does your word say shop or sop?'' Remind them of the two letters needed for /sh/.', 'Which two letters work together to make the first sound in that word?', '{"default":{"words":["shop","chip","thin"]},"ug":{"words":["shop","chip","thin"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L2_B', 'ENG_PS2c', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''ship''. Say it loud. Now, change the /sh/ sound to a /ch/ sound. Say the new word, then write it.', 'Child writes ''ship'', says ''chip'', and writes ''chip''.', 'If incorrect, point to the ''sh'' and ask what it says, then ask what ''ch'' says.', 'What letters did you have to change to make the new word?', '{"default":{"ladders":[["ship","chip"],["thin","chin"]]},"ug":{"ladders":[["shop","chop"],["thin","chin"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L2_C', 'ENG_PS2c', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''The fish took a bath.'' Say it back to me, then write it down.', 'Child repeats and accurately spells ''fish'' (ending ''sh'') and ''bath'' (ending ''th'').', 'If digraphs are misspelled, isolate the word: ''What two letters make the /sh/ sound at the end of fish?''', 'Look at the end of the word ''bath''. What two letters are making the final sound?', '{"default":{"sentences":["The fish took a bath."]},"ug":{"sentences":["The fish took a bath."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L3_A', 'ENG_PS2c', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Read this sentence carefully: ''The dog sat in the s-a-d-e.'' That doesn''t look right. What word should it be, and how do we spell the sound at the beginning?', 'Child identifies the word should be ''shade'' and that ''sh'' is missing.', 'If they read it as ''shade'', ask them to look at the letters again. ''Does s-a-d-e say shade?''', 'Why do we need an ''h'' after the ''s'' in this word?', '{"default":{"sentence":"The dog sat in the sade.","error":"sade","fix":"shade"},"ug":{"sentence":"The dog sat in the sade.","error":"sade","fix":"shade"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L3_B', 'ENG_PS2c', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to this silly sentence: ''I need to s-o-p vegetables for dinner.'' Did I say that correctly?', 'Child identifies the error and corrects it to ''chop''.', 'If missed, repeat: ''Does s-o-p sound like what you do to vegetables?''', 'What two letters should be at the beginning of ''chop''?', '{"default":{"sentence":"I need to sop vegetables for dinner.","error":"sop","fix":"chop"},"ug":{"sentence":"I need to sop the cabbage for dinner.","error":"sop","fix":"chop"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L3_C', 'ENG_PS2c', 3, 'C', 'Fill in the blank', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here is a word: ''__ip''. We want it to be the word for a big boat. Should we put ''sh'', ''ch'', or ''th'' at the beginning?', 'Child selects ''sh'' to make ''ship''.', 'If incorrect, read the options aloud: ''chip? thip?''', 'Why wouldn''t ''ch'' work in this blank?', '{"default":{"target":"ship","options":["sh","ch","th"],"clue":"a big boat"},"ug":{"target":"ship","options":["sh","ch","th"],"clue":"a big boat on the lake"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_A', 'ENG_PS2c', 4, 'A', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'How would you explain the difference between a blend (like ''sl'') and a digraph (like ''sh'') to someone learning to read? Write down one example of each.', 'Child explains that a blend is two sounds pushed together, but a digraph is two letters making one completely new sound.', 'If they struggle, ask: ''In sl-, can you hear the s and the l? In sh-, can you hear the s and the h?''', 'Why is ''sh'' a digraph and not a blend?', '{"default":{"concept":"blend vs digraph"},"ug":{"concept":"blend vs digraph"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_B', 'ENG_PS2c', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of a word that ends in ''th'', like ''math'' or ''bath''. Tell me a sentence using that word, and then write it down.', 'Child orally composes and writes a sentence using a word with a final ''th'' digraph.', 'If they pick a word starting with ''th'' (like ''the''), redirect them to find one that ends with it.', 'Point to the two letters that make the /th/ sound in your sentence.', '{"default":{"target":"ends in ''th''"},"ug":{"target":"ends in ''th''"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_C', 'ENG_PS2c', 4, 'C', 'Categorisation & Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Make two columns on your paper. Label one ''Starts with CH'' and the other ''Starts with SH''. Write two real words in each column. Say them aloud as you write them.', 'Child accurately generates two ''ch'' words and two ''sh'' words and places them in the correct columns.', 'If they struggle to think of words, offer clues (e.g., ''What do you do with an axe?'' -> chop).', 'How are the sounds in the first column different from the sounds in the second column?', '{"default":{"columns":["ch","sh"]},"ug":{"columns":["ch","sh"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2c_L4_M', 'ENG_PS2c', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We need to leave a short note. Think of a short sentence telling someone to do something, using a word with ''sh'' or ''ch'' (like ''shut the door'' or ''chop the wood''). Say the sentence to me, then write the note.', 'Child correctly composes and writes a functional sentence utilizing a digraph.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Read the note back to me. Did you use the two letters that work together to make one sound?', '{"default":{"examples":["shut the door","chop the wood"]},"ug":{"examples":["shut the door","chop the wood"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L1_A', 'ENG_PS2d', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to the word ''mad''. Now listen to the word ''made''. How did the vowel sound in the middle change?', 'Child identifies that ''mad'' has a short /a/ and ''made'' has a long /a/ (saying its name).', 'If they struggle, say ''m-aaaa-d'' vs ''m-ayyyy-d'' slowly.', 'What is the difference between the vowel sound in mad and made?', '{"default":{"pairs":[["mad","made"],["hop","hope"],["sit","site"]]},"ug":{"pairs":[["tap","tape"],["not","note"],["bit","bite"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L1_B', 'ENG_PS2d', 1, 'B', 'Physical Manipulation', 'Paper, Pencil, A small stick or pencil to act as a ''magic wand''', NULL, NULL, NULL, NULL, 'Write ''tap''. Now, use your ''magic e'' wand (pencil) and point to the end of the word. The ''e'' tells the vowel to say its name. Say the new word.', 'Child touches the end of the word and says ''tape''.', 'If they say ''tap-e'', remind them the ''e'' is silent, it just does magic on the vowel.', 'What does the magic ''e'' tell the vowel to do?', '{"default":{"words":["tap","kit","rob"]},"ug":{"words":["tap","kit","not"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L1_C', 'ENG_PS2d', 1, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at these two words: ''ran'' and ''rain''. In the second word, the ''a'' and ''i'' are a team working together. The first one does the talking and says its name. What does ''rain'' say?', 'Child correctly reads ''rain''.', 'If they read ''ran-in'', explain the vowel team rule: ''When two vowels go walking, the first one does the talking.''', 'Which letter does the talking in ''ai''?', '{"default":{"words":[["ran","rain"],["met","meet"],["got","goat"]]},"ug":{"words":[["ran","rain"],["bed","bead"],["cot","coat"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L2_A', 'ENG_PS2d', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a word that has a long vowel sound. You need a magic ''e'' at the end to make it happen. The word is ''cake''. Say it, stretch it, write it.', 'Child says /c/ /a/ /k/ and writes ''cake''.', 'If they write ''cak'', ask: ''Does this say cake or cak? What is missing?''', 'Why did you put an ''e'' at the end of the word?', '{"default":{"words":["cake","bike","home","cute"]},"ug":{"words":["cake","bite","hole","tube"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L2_B', 'ENG_PS2d', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write ''boat''. Now, change the first letter to make it say ''coat''. Say the new word, then write it. Remember the vowel team ''oa''.', 'Child writes ''boat'', says ''coat'', and writes ''coat''.', 'If they spell ''cote'', remind them we are using the vowel team ''oa'' for this list.', 'What two letters make the long /o/ sound in coat?', '{"default":{"words":[["boat","coat"],["rain","train"]]},"ug":{"words":[["boat","goat"],["rain","train"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L2_C', 'ENG_PS2d', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''Take the bike to the gate.'' Say it back to me, then write it down.', 'Child repeats the sentence and correctly spells ''take'', ''bike'', and ''gate'' using the magic ''e''.', 'If a word is spelled wrong, focus on the missing silent ''e''.', 'Look at the words take, bike, and gate. What do they all have at the end?', '{"default":{"sentences":["Take the bike to the gate."]},"ug":{"sentences":["Take the bike to the gate."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L3_A', 'ENG_PS2d', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Read this sentence: ''I h-o-p to see you soon.'' Look at the word ''hop''. Should it be hop, or hope? How do we fix it?', 'Child identifies the error, says ''hope'', and adds an ''e''.', 'If they don''t see it, ask them to read the sentence literally. ''I hop to see you soon.''', 'Why does adding an ''e'' change hop into hope?', '{"default":{"sentence":"I hop to see you soon.","error":"hop","fix":"hope"},"ug":{"sentence":"I hop to see you soon.","error":"hop","fix":"hope"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L3_B', 'ENG_PS2d', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to my sentence: ''The t-r-a-n is on the tracks.'' Did I pronounce that correctly for a big machine on tracks?', 'Child identifies the error and corrects it to ''train''.', 'If they agree, say: ''Tran? Or train?''', 'What sound did I miss in the middle of ''train''?', '{"default":{"sentence":"The t-r-a-n is on the tracks.","error":"tran","fix":"train"},"ug":{"sentence":"The b-o-t is on the lake.","error":"bot","fix":"boat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L3_C', 'ENG_PS2d', 3, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Read these nonsense words and tell me if the vowel says its name (long) or not: ''plame'', ''snib'', ''foat'', ''drit''.', 'Child correctly identifies ''plame'' and ''foat'' as having long vowels based on their spelling patterns.', 'If incorrect, point out the ''e'' on ''plame'' and the ''oa'' in ''foat''.', 'How did you know ''plame'' has a long /a/ sound even though it''s not a real word?', '{"default":{"words":["plame","snib","foat","drit"]},"ug":{"words":["plame","snib","foat","drit"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L4_A', 'ENG_PS2d', 4, 'A', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Teach someone younger the ''magic e'' rule. How does the ''e'' at the end change the vowel in the middle? Write down two words to prove it, showing the short version and the long version.', 'Child explains the rule accurately and provides examples like cap/cape, bit/bite.', 'If they struggle to explain, have them just do the example first.', 'Does the ''e'' make a sound itself?', '{"default":{"concept":"magic e"},"ug":{"concept":"magic e"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L4_B', 'ENG_PS2d', 4, 'B', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the vowel team ''ee'' at the top of your paper. Think of three words that use this team, say them out loud, and write them down.', 'Child correctly generates and spells three words with ''ee'' (e.g., tree, see, meet).', 'If they struggle, provide clues: ''What do you do with your eyes?''', 'What sound does the ''ee'' team make?', '{"default":{"vowel_team":"ee"},"ug":{"vowel_team":"ee"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L4_C', 'ENG_PS2d', 4, 'C', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Make up a short sentence that has at least two words with a magic ''e'' (like ''bike'' or ''gate''). Tell me the sentence, and then write it.', 'Child composes and writes a sentence utilizing at least two CVCe words.', 'If they can''t think of words, give them a list to choose from (make, time, nose, cute).', 'Read your sentence back. Point to the words with the magic ''e''.', '{"default":{"constraint":"two magic e words"},"ug":{"constraint":"two magic e words"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2d_L4_M', 'ENG_PS2d', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We need to make a sign for a game. Think of a short rule that uses a long vowel word (like ''Wait here'' or ''Make a line''). Say your rule to me, then write the sign.', 'Child orally composes and accurately spells a phrase using a long vowel pattern.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Show me the word in your sign that has a long vowel sound. How did you spell it?', '{"default":{"examples":["Wait here","Make a line"]},"ug":{"examples":["Wait here","Make a line"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L1_A', 'ENG_PS2e', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to these words: ''cat'', ''car''. The ''r'' in ''car'' is bossy. It changes how the ''a'' sounds. Which word has the bossy ''r'' sound: ''mat'' or ''star''?', 'Child identifies ''star''.', 'If incorrect, exaggerate the sounds: /a/ vs /ar/.', 'What does the bossy ''r'' do to the vowel before it?', '{"default":{"words":[["mat","star"],["hen","her"],["sit","sir"]]},"ug":{"words":[["mat","star"],["pen","her"],["pit","sir"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L1_B', 'ENG_PS2e', 1, 'B', 'Verbal Identification', 'None', NULL, NULL, NULL, NULL, 'I will say a word. If it has the /ar/ sound like ''car'', say ''vroom!''. Ready? ''Farm''. ''Pat''. ''Dark''.', 'Child responds appropriately (''vroom'' for farm, dark).', 'If they miss one, isolate the sound.', 'What two letters make that /ar/ sound?', '{"default":{"words":[["farm",true],["pat",false],["dark",true]]},"ug":{"words":[["park",true],["pan",false],["dark",true]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L1_C', 'ENG_PS2e', 1, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at these words: ''her'', ''bird'', ''fur''. They all sound exactly the same in the middle (/er/), but they are spelled differently. Which one uses ''i-r''?', 'Child points to ''bird''.', 'If they misread, explain that er, ir, and ur all make the same bossy ''r'' sound.', 'Even though they are spelled differently, what sound do they all make?', '{"default":{"words":["her","bird","fur"]},"ug":{"words":["her","bird","fur"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L2_A', 'ENG_PS2e', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a word. You say the sounds, and then write the letters. The word is ''star''. Remember the bossy ''r''!', 'Child says /s/ /t/ /ar/ and writes ''star''.', 'If they write ''ster'' or ''star'', gently correct the spelling pattern.', 'Which two letters made the /ar/ sound?', '{"default":{"words":["star","fork","yard","horn"]},"ug":{"words":["star","fork","yard","horn"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L2_B', 'ENG_PS2e', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''cat''. Now, insert an ''r'' right after the ''a''. Say the new word, then write it.', 'Child writes ''cat'', says ''cart'', and writes ''cart''.', 'If they put the ''r'' at the end (''catr''), point to the spot after the ''a''.', 'How did the vowel sound change when we added the ''r''?', '{"default":{"words":[["cat","cart"],["hut","hurt"]]},"ug":{"words":[["pot","port"],["hut","hurt"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L2_C', 'ENG_PS2e', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Repeat this sentence, then write it: ''The bird sat on the car.''', 'Child repeats and spells ''bird'' (ir) and ''car'' (ar) correctly.', 'If they misspell ''bird'' as ''berd'' or ''burd'', tell them ''bird uses the i-r pattern.''', 'What letters make the bossy ''r'' sound in ''bird''?', '{"default":{"sentences":["The bird sat on the car."]},"ug":{"sentences":["The bird sat on the car."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L3_A', 'ENG_PS2e', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Read this sentence: ''I want f-o-k with my dinner.'' Wait, that''s not how we spell the tool we eat with. What is missing?', 'Child identifies that ''fork'' needs an ''r''.', 'If they don''t see it, read it out loud exactly as written.', 'Why do we need the ''r'' in fork?', '{"default":{"sentence":"I want fok with my dinner.","error":"fok","fix":"fork"},"ug":{"sentence":"I want fok with my dinner.","error":"fok","fix":"fork"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L3_B', 'ENG_PS2e', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to this: ''The dog began to b-a-c-k.'' Did I use the right word for the sound a dog makes?', 'Child identifies it should be ''bark''.', 'If they say yes, ask: ''Does a dog back or bark?''', 'What sound did I forget to say?', '{"default":{"sentence":"The dog began to b-a-c-k.","error":"back","fix":"bark"},"ug":{"sentence":"The dog began to b-a-c-k.","error":"back","fix":"bark"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L3_C', 'ENG_PS2e', 3, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here are three ways someone tried to spell the word for a young girl: ''garl'', ''gerl'', ''girl''. Which one is the right spelling?', 'Child selects ''girl''.', 'If they choose ''gerl'', explain that ir, ur, and er sound the same, so we just have to memorize which one ''girl'' uses.', 'Why is it tricky to spell words with the /er/ sound?', '{"default":{"word":"girl","options":["garl","gerl","girl"]},"ug":{"word":"girl","options":["garl","gerl","girl"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L4_A', 'ENG_PS2e', 4, 'A', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write ''ar'' at the top of your paper. Say the sound out loud. Now, write down three different words that have the ''ar'' sound in them.', 'Child successfully lists three words like car, far, star, park.', 'If they get stuck, give hints: ''Where do you play outside?''', 'Read your words. Do they all have the bossy ''r'' sound?', '{"default":{"sound":"ar"},"ug":{"sound":"ar"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L4_B', 'ENG_PS2e', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Tell me a short sentence about an animal using a word that has ''or'' in it (like ''horse'' or ''horn''). Say the sentence, then write it.', 'Child orally composes and writes a sentence utilizing an ''or'' word.', 'If they pick an animal without ''or'', remind them of the rule.', 'Which word has the ''or'' sound?', '{"default":{"target":"or"},"ug":{"target":"or"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L4_C', 'ENG_PS2e', 4, 'C', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to me what ''bossy r'' means. What does the ''r'' do to the vowel that comes right before it? Give me one example.', 'Child explains that the ''r'' changes the vowel''s normal sound and provides a correct example.', 'If they can''t explain, have them write ''cat'' and ''cart'' and explain the difference.', 'Why do we call it bossy?', '{"default":{"concept":"bossy r"},"ug":{"concept":"bossy r"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2e_L4_M', 'ENG_PS2e', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We are going to make a short list of things outside. Think of two things you might see outside that have the bossy ''r'' sound (like a car, a bird, or dirt). Say them to me, and then write them down.', 'Child accurately identifies and spells two bossy ''r'' words based on observation or recall.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Point to the letters in your words that are making the bossy ''r'' sound.', '{"default":{"examples":["car","bird","dirt"]},"ug":{"examples":["car","bird","dirt"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L1_A', 'ENG_PS2f', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to the word ''basket''. Let''s clap the parts we hear: bas-ket. How many claps was that?', 'Child identifies 2 syllables/claps.', 'If they clap once or three times, model it again slowly.', 'How many vowel sounds do you hear in ''basket''?', '{"default":{"words":[["basket",2],["cat",1],["banana",3]]},"ug":{"words":[["basket",2],["cup",1],["matooke",3]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L1_B', 'ENG_PS2f', 1, 'B', 'Physical Manipulation', 'Paper, Scissors (or pencil to draw a line)', NULL, NULL, NULL, NULL, 'Write the word ''muffin'' big on a piece of paper. Say it loud: muf-fin. Where do you hear the split? Use the scissors (or pencil) to cut the word right between the two syllables.', 'Child cuts or draws a line between ''muf'' and ''fin'' (between the double consonants).', 'If they split it wrong, clap the syllables while looking at the word.', 'Why did you split it right between the two ''f''s?', '{"default":{"word":"muffin"},"ug":{"word":"cotton"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L1_C', 'ENG_PS2f', 1, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at the word ''hi''. The vowel is at the very end, so it''s ''open'' and says its name. Look at ''him''. The ''m'' closes the door, so the vowel is short. Which one has a closed door: ''me'' or ''met''?', 'Child identifies ''met'' as having a closed door (consonant at the end).', 'If wrong, explain the ''door'' analogy again.', 'What letter closes the door in ''met''?', '{"default":{"pairs":[["me","met"],["no","not"]]},"ug":{"pairs":[["me","met"],["no","not"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L2_A', 'ENG_PS2f', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a long word, but we will write it one chunk at a time. The word is ''sunset''. First, say ''sun'' and write it. Now say ''set'' and write it right next to it.', 'Child writes ''sunset'' accurately by dividing it orally.', 'If they miss letters, have them sound out each chunk separately.', 'How does breaking a big word into chunks make it easier to spell?', '{"default":{"words":["sunset","picnic","napkin"]},"ug":{"words":["sunset","picnic","dustbin"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L2_B', 'ENG_PS2f', 2, 'B', 'Visual Manipulation & Encoding', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''rabbit''. Now, draw a line to split it into two syllables. Read the first part, then the second part.', 'Child writes ''rabbit'' and draws a line between the b''s (rab/bit).', 'If they split it ra/bbit, remind them to split between double consonants.', 'What happens when we have two consonants between vowels? Where do we split it?', '{"default":{"words":["rabbit","kitten","sudden"]},"ug":{"words":["rabbit","kitten","sudden"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L2_C', 'ENG_PS2f', 2, 'C', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''go''. Say it. Now, add a ''t'' to the end to close the door. What is the new word? Write it.', 'Child writes ''go'', says ''got'', and writes ''got''.', 'If they say ''goat'', remind them that closing the door makes the vowel short.', 'How did the sound of the ''o'' change when we closed the door?', '{"default":{"words":[["go","got"],["be","bed"]]},"ug":{"words":[["so","sop"],["he","hen"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L3_A', 'ENG_PS2f', 3, 'A', 'Error Detection', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Someone tried to split the word ''basket'' into syllables. They wrote ''ba-sket''. Is that where the word splits?', 'Child identifies that it should be ''bas-ket''.', 'If they agree with ''ba-sket'', clap it out loud: bas-ket.', 'Why do we split between the ''s'' and the ''k''?', '{"default":{"word":"basket","error":"ba-sket","fix":"bas-ket"},"ug":{"word":"market","error":"ma-rket","fix":"mar-ket"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L3_B', 'ENG_PS2f', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'I''m going to clap the syllables in the word ''butterfly''. *clap twice*. Did I get it right?', 'Child says no and correctly claps three times.', 'If they miss it, say ''but-ter-fly'' slowly while counting on fingers.', 'How many parts does the word ''butterfly'' have?', '{"default":{"word":"butterfly","error":2,"fix":3},"ug":{"word":"pineapple","error":2,"fix":3}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L3_C', 'ENG_PS2f', 3, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at these two words: ''robot'' and ''rabbit''. Which word has an open first syllable (where the vowel says its name)?', 'Child selects ''robot'' (ro-bot).', 'If they choose ''rabbit'' (rab-bit), remind them that the ''b'' closes the door on the ''a''.', 'Why does the ''o'' in robot say its name?', '{"default":{"options":["robot","rabbit"]},"ug":{"options":["robot","rabbit"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L4_A', 'ENG_PS2f', 4, 'A', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of three words that have exactly two syllables. Say them out loud, clap them to check, and then write them down.', 'Child successfully lists three 2-syllable words.', 'If they pick 1-syllable words, remind them they need to clap twice.', 'Read your words and clap as you read them.', '{"default":{"constraint":"two syllables"},"ug":{"constraint":"two syllables"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L4_B', 'ENG_PS2f', 4, 'B', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to me the difference between an open syllable (like ''no'') and a closed syllable (like ''not''). Write the two words down to help you explain.', 'Child accurately explains the concept of the consonant ''closing the door'' and changing the vowel sound.', 'If they struggle, ask: ''Which one has a vowel that says its name?''', 'What happens to the vowel sound when we close the syllable?', '{"default":{"concept":"open vs closed syllables"},"ug":{"concept":"open vs closed syllables"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L4_C', 'ENG_PS2f', 4, 'C', 'Creative Spelling', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Invent a silly, long alien name that has three syllables. Clap the syllables to me, and then write the name down spelling each chunk the way it sounds.', 'Child claps 3 syllables and writes a phonetically plausible string of letters (e.g., Zib-lok-nam).', 'If they just write random letters, have them do one syllable at a time.', 'Show me the three chunks you wrote. What vowels are in each chunk?', '{"default":{"theme":"alien name"},"ug":{"theme":"alien name"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2f_L4_M', 'ENG_PS2f', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We are making a list of things to pack for a trip. Write down ''blanket'' and ''jacket''. Think about how many syllables are in each word to help you spell them.', 'Child writes ''blanket'' and ''jacket'' accurately, utilizing syllable division strategies if needed.', 'Do not correct during the task. If spelling fails heavily, review Execute level tasks.', 'How did breaking the word into chunks help you spell it?', '{"default":{"words":["blanket","jacket"]},"ug":{"words":["blanket","jacket"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L1_A', 'ENG_PS2g', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to these words: ''light'', ''night'', ''right''. They all rhyme. What sound do you hear at the end of all of them?', 'Child identifies the /ite/ sound.', 'If they just say /t/, encourage them to listen to the whole chunk.', 'What other word rhymes with light and night?', '{"default":{"words":["light","night","right"]},"ug":{"words":["light","night","right"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L1_B', 'ENG_PS2g', 1, 'B', 'Visual Discrimination', 'A book or printed text', NULL, NULL, NULL, NULL, 'Look at this page. The letters ''i-g-h-t'' work together to make the /ite/ sound. Find a word on this page that has that pattern.', 'Child locates a word with the -ight pattern.', 'If they can''t find it, point out a few words and ask if they have the pattern.', 'What do those four letters say when they are together?', '{"default":{"pattern":"ight"},"ug":{"pattern":"ight"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L1_C', 'ENG_PS2g', 1, 'C', 'Physical Manipulation', 'Letter tiles: h, o, p, p, i, n, g', NULL, NULL, NULL, NULL, 'Here is the word ''hop''. We want to make it ''hopping''. If we just add ''ing'', the ''i'' makes the ''o'' long, and it says ''hoping''. We need an extra ''p'' to act like a wall to protect the short ''o''. Put the extra ''p'' in.', 'Child physically places the second ''p'' before the ''ing''.', 'If they don''t understand, demonstrate with and without the extra ''p''.', 'Why did we need two ''p''s in hopping?', '{"default":{"word":"hopping"},"ug":{"word":"hopping"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L2_A', 'ENG_PS2g', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'The letters i-g-h-t say /ite/. I am going to say a word. You say it, then write it. The word is ''might''.', 'Child writes ''might'' accurately.', 'If they write ''mite'', remind them we are practicing the 4-letter pattern today.', 'Which four letters make the /ite/ sound in this word?', '{"default":{"words":["might","high","bright"]},"ug":{"words":["might","high","bright"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L2_B', 'ENG_PS2g', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the word ''run''. Say it loud. Now, we want to write ''running''. Remember, ''run'' has a short vowel, so we must double the consonant before adding ''ing''. Write ''running''.', 'Child writes ''run'', says ''running'', and writes ''running'' with a double ''n''.', 'If they write ''runing'', ask: ''Did you build the wall to protect the short u?''', 'Why did we need two ''n''s?', '{"default":{"words":[["run","running"],["sit","sitting"]]},"ug":{"words":[["run","running"],["sit","sitting"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L2_C', 'ENG_PS2g', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''Turn on the bright light.'' Say it back to me, then write it.', 'Child repeats and spells ''bright'' and ''light'' using the -ight pattern.', 'If misspelled, isolate the word and ask what 4 letters make that sound.', 'What spelling pattern do bright and light share?', '{"default":{"sentences":["Turn on the bright light."]},"ug":{"sentences":["Turn on the bright light."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L3_A', 'ENG_PS2g', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Read this: ''We look at the stars at n-i-t-e.'' Is that the standard way to spell the word ''night''?', 'Child identifies it should be spelled ''night''.', 'If they think ''nite'' is fine, explain that while people sometimes write it that way, the correct pattern is i-g-h-t.', 'What four letters should make the /ite/ sound in night?', '{"default":{"sentence":"We look at the stars at nite.","error":"nite","fix":"night"},"ug":{"sentence":"We look at the stars at nite.","error":"nite","fix":"night"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L3_B', 'ENG_PS2g', 3, 'B', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at these two words: ''hoping'' and ''hopping''. Which one means you are jumping up and down on one foot?', 'Child selects ''hopping''.', 'If they choose ''hoping'', review the short vowel vs long vowel doubling rule.', 'What does the word ''hoping'' mean?', '{"default":{"options":["hoping","hopping"],"target":"jumping"},"ug":{"options":["hoping","hopping"],"target":"jumping"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L3_C', 'ENG_PS2g', 3, 'C', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'If I want to write the word ''cutting'', do I need two ''t''s in the middle, or just one? Listen to the vowel sound in ''cut''.', 'Child states two ''t''s are needed.', 'If they say one, ask: ''Is the u in cut short or long? If it''s short, we need to protect it with two consonants.''', 'Why do we need two ''t''s for cutting?', '{"default":{"word":"cutting"},"ug":{"word":"cutting"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L4_A', 'ENG_PS2g', 4, 'A', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write ''-ight'' at the top of your paper. Write three words that rhyme with ''light'' using that pattern.', 'Child accurately lists three -ight words.', 'If stuck, offer initial sounds (f, m, s).', 'Read your words. Do they all rhyme?', '{"default":{"pattern":"ight"},"ug":{"pattern":"ight"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L4_B', 'ENG_PS2g', 4, 'B', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to me the rule for adding ''-ing'' to a word like ''sit''. What do you have to do before you add the ''-ing''? Write the word down to show me.', 'Child explains that the ''t'' must be doubled, and writes ''sitting''.', 'If they can''t explain it, prompt them: ''What happens if we don''t add the second t?''', 'Why do we double the last letter?', '{"default":{"concept":"doubling rule"},"ug":{"concept":"doubling rule"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L4_C', 'ENG_PS2g', 4, 'C', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Make up a sentence using the word ''swimming''. Think carefully about the spelling rule before you write it down.', 'Child composes and accurately spells a sentence containing ''swimming'' (double m).', 'If they write ''swiming'', ask them to review the doubling rule.', 'How did you spell swimming? Why did you spell it that way?', '{"default":{"target":"swimming"},"ug":{"target":"swimming"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2g_L4_M', 'ENG_PS2g', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write a short sentence about something you like doing (like ''running'' or ''reading''). Think carefully about whether you need to double any letters before adding ''-ing''. Say the sentence to me, then write it.', 'Child composes a sentence and accurately applies or avoids the doubling rule when adding -ing to their chosen verb.', 'Do not correct during the task. If spelling fails, review Execute level tasks.', 'Show me the word ending in ''-ing''. Did you double the consonant? Why or why not?', '{"default":{"examples":["running","reading"]},"ug":{"examples":["running","reading"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L1_A', 'ENG_PS2h', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to the word ''happy''. Now listen to ''unhappy''. What little chunk of sound did I add to the beginning of the second word?', 'Child identifies ''un''.', 'If they don''t catch it, say ''un-happy''.', 'What does ''un'' mean when we put it in front of happy?', '{"default":{"words":["happy","unhappy"]},"ug":{"words":["happy","unhappy"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L1_B', 'ENG_PS2h', 1, 'B', 'Physical Manipulation', 'Three small pieces of paper with ''un'', ''do'', and ''ing'' written on them', NULL, NULL, NULL, NULL, 'The middle paper says ''do''. That is the root word. If we put ''un'' in front of it, what does it say? If we take ''un'' away and put ''ing'' at the end, what does it say?', 'Child physically moves the papers and reads ''undo'' and ''doing''.', 'If they misread, point to each part: un + do.', 'How does the meaning of ''do'' change when we add ''un''?', '{"default":{"root":"do","affixes":["un","ing"]},"ug":{"root":"do","affixes":["un","ing"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L1_C', 'ENG_PS2h', 1, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at these words: ''help'', ''helpful'', ''helpless''. They all share the same root word. Circle the root word ''help'' hidden inside the two longer words.', 'Child successfully circles ''help'' inside ''helpful'' and ''helpless''.', 'If they circle the whole word, show them how to cover up the ending to see the root.', 'What does the ending ''-ful'' mean? What does ''-less'' mean?', '{"default":{"words":["help","helpful","helpless"]},"ug":{"words":["help","helpful","helpless"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L2_A', 'ENG_PS2h', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will say a word with a prefix. Think of the root word first, then add the prefix chunk. The word is ''rebuild''. Say it, then write it.', 'Child writes ''rebuild'' accurately.', 'If misspelled, isolate the chunks: ''How do you spell the prefix re-? How do you spell the root build?''', 'What does the prefix ''re-'' mean in the word rebuild?', '{"default":{"words":["rebuild","unlock","remake"]},"ug":{"words":["rebuild","unlock","remake"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L2_B', 'ENG_PS2h', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the root word ''hope''. Now, we want to add the suffix ''-ful''. Remember, when the root ends in a magic ''e'' and the suffix starts with a consonant, we just stick them together. Write ''hopeful''.', 'Child writes ''hope'', says ''hopeful'', and writes ''hopeful''.', 'If they drop the ''e'' (''hopful''), remind them of the rule.', 'Did we keep the ''e'' or drop it? Why?', '{"default":{"words":[["hope","hopeful"],["care","careless"]]},"ug":{"words":[["hope","hopeful"],["care","careless"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L2_C', 'ENG_PS2h', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''He was very helpful.'' Say it back to me, then write it down.', 'Child repeats and spells ''helpful'' correctly, identifying root and suffix.', 'If they misspell ''helpful'' (e.g., ''helpfull''), point out that the suffix ''-ful'' only has one ''l''.', 'What is the root word in ''helpful''? What is the suffix?', '{"default":{"sentences":["He was very helpful."]},"ug":{"sentences":["He was very helpful."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L3_A', 'ENG_PS2h', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Look at this sentence: ''The puppy is very playfull.'' Find the mistake in how the suffix is spelled.', 'Child identifies that the suffix ''-ful'' should only have one ''l''.', 'If they miss it, write ''full'' and ''-ful'' side by side and explain the difference.', 'When ''-ful'' is attached to a word as a suffix, how many ''l''s does it have?', '{"default":{"sentence":"The puppy is very playfull.","error":"playfull","fix":"playful"},"ug":{"sentence":"The dog is very playfull.","error":"playfull","fix":"playful"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L3_B', 'ENG_PS2h', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''I tied my shoes, but then I had to re-tie them because I did it wrong.'' Does ''re-tie'' make sense there? What does ''re-'' mean?', 'Child confirms ''re-tie'' makes sense and means ''tie again''.', 'If they say ''un-tie'', explain: ''If I did it wrong, I want to do it again (re-), not undo it (un-).''', 'If I wanted to take my shoes off, what prefix would I use instead of ''re-''?', '{"default":{"word":"re-tie","meaning":"tie again"},"ug":{"word":"re-tie","meaning":"tie again"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L3_C', 'ENG_PS2h', 3, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Here are three words: ''unlock'', ''under'', ''unhappy''. Two of these words have the prefix ''un-''. One of them just starts with the letters ''u-n'' but doesn''t have a prefix. Which one is the trick word?', 'Child identifies ''under'' because ''der'' is not a root word.', 'If they struggle, ask them to read the root word of each (lock, der, happy).', 'Why isn''t ''un-'' a prefix in the word ''under''?', '{"default":{"options":["unlock","under","unhappy"],"target":"under"},"ug":{"options":["unlock","under","unhappy"],"target":"under"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L4_A', 'ENG_PS2h', 4, 'A', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write the prefix ''un-'' at the top of your page. Now, list three root words that you can add ''un-'' to, to make real words (like ''un-do'' or ''un-lock''). Write the full words.', 'Child successfully lists three valid words starting with ''un-''.', 'If they list words like ''under'' or ''uncle'', remind them to check if the root is a real word.', 'Cover up the ''un-'' in each of your words. Are the words underneath real words?', '{"default":{"prefix":"un-"},"ug":{"prefix":"un-"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L4_B', 'ENG_PS2h', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of a word that ends with the suffix ''-less'' (like ''careless'' or ''fearless''). Tell me a sentence using that word, and then write it down.', 'Child composes and writes a sentence utilizing a word ending in ''-less''.', 'If they don''t know the meaning, remind them that ''-less'' means ''without''.', 'What does your word mean in that sentence? (e.g., fearless = without fear).', '{"default":{"suffix":"-less"},"ug":{"suffix":"-less"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L4_C', 'ENG_PS2h', 4, 'C', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain the difference between a prefix (like ''re-'') and a suffix (like ''-ful''). Where do they go on a root word, and what do they do? Write an example of each.', 'Child explains that prefixes go at the beginning, suffixes at the end, and both change the meaning of the root.', 'If they get confused, have them draw a train with an engine (prefix), car (root), and caboose (suffix).', 'How does adding an affix change a word?', '{"default":{"concept":"prefix vs suffix"},"ug":{"concept":"prefix vs suffix"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2h_L4_M', 'ENG_PS2h', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write a short note telling someone not to do something again. Use a word that starts with the prefix ''re-'' (like ''rebuild'', ''rewrite'', or ''remake''). Say the sentence, then write it.', 'Child orally composes and accurately writes a sentence using a word with the prefix ''re-''.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Show me the word with the prefix. What is the root word hiding inside it?', '{"default":{"constraint":"use ''re-'' prefix"},"ug":{"constraint":"use ''re-'' prefix"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L1_A', 'ENG_PS2i', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''I was going to the store.'' Listen again: ''I was going to the store.'' Which word sounds like /wuz/?', 'Child identifies ''was''.', 'If they say ''wuz'' is not in the sentence, repeat the sentence slowly.', 'Why is ''was'' a tricky word to spell?', '{"default":{"sentence":"I was going to the store."},"ug":{"sentence":"I was going to the shop."}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L1_B', 'ENG_PS2i', 1, 'B', 'Physical Manipulation', 'Paper, Pencil or finger', NULL, NULL, NULL, NULL, 'Look at the word ''said''. It is a tricky word because it doesn''t follow the rules. Trace the letters with your finger while you spell it out loud: s-a-i-d. What does it say?', 'Child traces the letters and reads ''said''.', 'If they try to sound it out phonetically (/s/ /a/ /i/ /d/), remind them it''s a ''heart word'' we have to memorize by heart.', 'Which part of the word ''said'' is the tricky part?', '{"default":{"word":"said"},"ug":{"word":"said"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L1_C', 'ENG_PS2i', 1, 'C', 'Visual Discrimination', 'A book or printed text', NULL, NULL, NULL, NULL, 'Look at this page in your book. The word ''they'' is spelled t-h-e-y. It''s very common. See how many times you can find the word ''they'' on this page in one minute.', 'Child locates the word ''they'' multiple times.', 'If they miss it, write ''they'' big on a piece of paper to act as a model to match.', 'How do you spell the word ''they''?', '{"default":{"word":"they"},"ug":{"word":"they"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L2_A', 'ENG_PS2i', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a tricky sight word. Say the letters out loud as you write it. The word is ''could''. (c-o-u-l-d).', 'Child writes ''could'' from memory.', 'If misspelled, show them the correct spelling, have them trace it 3 times saying the letters, then hide it and try again.', 'What are the tricky silent letters in the middle of ''could''?', '{"default":{"words":["could","would","should"]},"ug":{"words":["could","would","should"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L2_B', 'ENG_PS2i', 2, 'B', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''They went to the park.'' Say it back, then write it.', 'Child accurately spells the high-frequency words ''they'', ''went'', ''to'', ''the''.', 'If ''they'' is spelled ''thay'', review the specific spelling of ''they''.', 'Point to the word ''they''. How did you spell it?', '{"default":{"sentences":["They went to the park.","He said to come here."]},"ug":{"sentences":["They went to the park.","He said to come here."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L2_C', 'ENG_PS2i', 2, 'C', 'Visual Memory Dictation', 'Paper, Pencil, Flashcard with the word ''because''', NULL, NULL, NULL, NULL, 'Look at the word ''because''. I''m going to hide it in 3 seconds. Try to take a picture of it in your brain. 1... 2... 3... (hide it). Now write it down.', 'Child writes ''because'' accurately from visual memory.', 'If misspelled, show the card again, point out the tricky part (a-u-s-e), and try again.', 'What trick helps you remember how to spell ''because''?', '{"default":{"words":["because","people","friend"]},"ug":{"words":["because","people","friend"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L3_A', 'ENG_PS2i', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Read this sentence: ''My f-r-e-n-d is nice.'' That word is spelled how it sounds, but it''s a tricky word so that spelling is wrong. How do we actually spell ''friend''?', 'Child identifies the missing ''i'' and spells ''friend''.', 'If they don''t know, write it out for them: ''f-r-i-e-n-d''.', 'Why can''t we just sound out the word ''friend''?', '{"default":{"sentence":"My frend is nice.","error":"frend","fix":"friend"},"ug":{"sentence":"My frend is nice.","error":"frend","fix":"friend"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L3_B', 'ENG_PS2i', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen to this: ''I have two eyes, so I can see.'' Now listen to this: ''I went two the store.'' Did I use the right ''two/to/too'' in both sentences?', 'Child identifies that ''went two the store'' is incorrect in meaning/spelling.', 'If they miss the homophone difference, explain two (number), too (also), and to (direction).', 'Which ''to'' means direction?', '{"default":{"sentences":["I went two the store.","I went to the store."]},"ug":{"sentences":["I went two the shop.","I went to the shop."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L3_C', 'ENG_PS2i', 3, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Which is the correct way to spell the word that means a group of humans: ''peeple'' or ''people''?', 'Child selects ''people''.', 'If they choose ''peeple'', remind them it''s a ''heart word'' that doesn''t follow the normal ''ee'' rule.', 'What are the tricky vowels in the middle of the word ''people''?', '{"default":{"options":["peeple","people"]},"ug":{"options":["peeple","people"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L4_A', 'ENG_PS2i', 4, 'A', 'Creative Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of three tricky sight words that you can''t just sound out perfectly (like ''was'', ''said'', or ''they''). Say them, then write them down from memory.', 'Child lists three non-phonetic high-frequency words.', 'If they write phonetic words (like ''cat''), ask: ''Can you sound out every letter in cat perfectly? Yes. Find a word where the letters lie to you.''', 'Pick one of your words. Which part of it is tricky?', '{"default":{"constraint":"non-phonetic words"},"ug":{"constraint":"non-phonetic words"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L4_B', 'ENG_PS2i', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Tell me a sentence using the word ''their'' (like ''their dog''). Then tell me a sentence using the word ''there'' (like ''over there''). Write both sentences.', 'Child orally composes and writes sentences using correct contextual spelling of there/their.', 'If they confuse them, review: ''their'' has an ''i'' for ''heir/person''; ''there'' has ''here'' inside it.', 'How do you remember which spelling to use for ''over there''?', '{"default":{"target":"there vs their"},"ug":{"target":"there vs their"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L4_C', 'ENG_PS2i', 4, 'C', 'Creative Story', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write a short, two-sentence story. You must use the words ''because'' and ''friend'' in your story. Tell it to me first, then write it.', 'Child orally composes and writes a short story utilizing and correctly spelling the target words.', 'If they misspell the target words, have them erase and correct just those words.', 'Point to the word ''because''. Read the letters to me.', '{"default":{"words":["because","friend"]},"ug":{"words":["because","friend"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2i_L4_M', 'ENG_PS2i', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We need to write a quick note to a friend. Write: ''I like you because you are fun.'' Say it out loud, then write it.', 'Child accurately spells the high-frequency words ''you'', ''because'', ''are''.', 'Do not correct during the task. If spelling fails heavily, review Execute level tasks.', 'Show me the word ''because'' on your note. How did you remember the tricky parts?', '{"default":{"sentence":"I like you because you are fun."},"ug":{"sentence":"I like you because you are fun."}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L1_A', 'ENG_PS2j', 1, 'A', 'Auditory Discrimination', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a big word: ''trumpet''. Let''s count the sounds we hear in the first chunk, ''trum''. T-r-u-m. How many sounds is that?', 'Child identifies 4 individual sounds.', 'If they say 1 or 2, stretch the sounds out very slowly while holding up a finger for each one.', 'What is the very first sound in ''trum''? What is the last sound?', '{"default":{"word":"trumpet"},"ug":{"word":"trumpet"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L1_B', 'ENG_PS2j', 1, 'B', 'Physical Manipulation', '4 small items (coins, blocks, or drawn boxes on paper)', NULL, NULL, NULL, NULL, 'We are going to map the word ''frog''. Say the word slowly and push a coin forward for every sound you hear: /f/ /r/ /o/ /g/. How many coins did you push?', 'Child pushes 4 coins, one for each phoneme.', 'If they push one coin for ''fr'', remind them that a blend is two separate sounds pushed together.', 'Which sound does the second coin stand for?', '{"default":{"word":"frog","phonemes":4},"ug":{"word":"frog","phonemes":4}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L1_C', 'ENG_PS2j', 1, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'Look at the word ''s-w-i-m''. Read the letters out loud. Does that word have all the sounds we need to say ''swim''?', 'Child confirms yes.', 'If they are confused, point to each letter while saying the sounds slowly.', 'What sound does the ''w'' make in that word?', '{"default":{"word":"swim"},"ug":{"word":"swim"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L2_A', 'ENG_PS2j', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a word you might not know how to spell. But you can figure it out. The word is ''pumpkin''. Say the first chunk (''pump''), say the sounds, write it. Then the next chunk (''kin'').', 'Child accurately segments and writes ''pumpkin''.', 'If they miss the ''p'' in ''pump'', have them stretch the sounds again: p-u-m-p.', 'How did breaking the word into chunks help you spell it?', '{"default":{"words":["pumpkin","plastic"]},"ug":{"words":["plastic","dustbin"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L2_B', 'ENG_PS2j', 2, 'B', 'Oral->Written Word Building', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Draw four little lines on your paper like this: _ _ _ _. We are going to spell ''stop''. What is the first sound? Write the letter on the first line. Next sound? Write it.', 'Child maps the 4 phonemes to the 4 lines accurately to spell ''stop''.', 'If they struggle, say the word extremely slowly so they hear every distinct sound.', 'Why do we need 4 lines for the word ''stop''?', '{"default":{"words":["stop","jump"]},"ug":{"words":["stop","jump"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L2_C', 'ENG_PS2j', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Repeat this sentence: ''The small crab hid in the sand.'' Say it back, then write it.', 'Child encodes complex consonant clusters (sm-, cr-, -nd) and digraphs accurately.', 'If they write ''cab'' for ''crab'', point to the word and ask what sounds are missing.', 'Look at the word ''crab''. Did you remember both sounds at the beginning?', '{"default":{"sentences":["The small crab hid in the sand."]},"ug":{"sentences":["The small crab hid in the sand."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L3_A', 'ENG_PS2j', 3, 'A', 'Error Detection', 'Paper with printed sentence', NULL, NULL, NULL, NULL, 'Someone tried to sound out the word ''jump''. They wrote ''j-u-p''. Read that word. What sound did they forget to encode?', 'Child identifies that ''m'' is missing.', 'If they can''t tell, stretch ''jump'' slowly and count the sounds on your fingers.', 'Why is it easy to forget the ''m'' in ''jump''?', '{"default":{"word":"jump","error":"jup","fix":"jump"},"ug":{"word":"jump","error":"jup","fix":"jump"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L3_B', 'ENG_PS2j', 3, 'B', 'Auditory Error Detection', 'None', NULL, NULL, NULL, NULL, 'Listen: ''I am going to d-r-i-n the water from the cup.'' Did I say ''drink'' correctly? What was missing?', 'Child identifies the missing /k/ sound at the end.', 'If they say yes, emphasize the end of the word ''drin-K''.', 'What letter makes the sound I forgot at the end?', '{"default":{"word":"drink","error":"drin"},"ug":{"word":"drink","error":"drin"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L3_C', 'ENG_PS2j', 3, 'C', 'Visual Discrimination', 'Paper with printed words', NULL, NULL, NULL, NULL, 'A little kid tried to write the word ''elephant''. They wrote ''e-l-e-f-i-n-t''. It''s not spelled perfectly, but did they do a good job capturing all the sounds they heard?', 'Child confirms yes, it phonetically makes sense.', 'If they just say ''it''s spelled wrong'', explain that encoding is about getting the sounds down first, even if the spelling rules are tricky (like ph for f).', 'Which part did they spell differently from the dictionary, but it still makes the same sound?', '{"default":{"word":"elephant","invented":"elefint"},"ug":{"word":"elephant","invented":"elefint"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L4_A', 'ENG_PS2j', 4, 'A', 'Creative Spelling', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I am going to say a very long word you probably haven''t spelled before: ''fantastic''. Break it into chunks. Clap the syllables. Now write it down just by listening to the sounds.', 'Child claps fan-tas-tic and writes ''fantastic'' (or highly accurate phonetic equivalent).', 'If they freeze, guide them: ''What is the first chunk? Fan. Spell fan.''', 'Read the chunks back to me. Did you capture every sound?', '{"default":{"word":"fantastic"},"ug":{"word":"fantastic"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L4_B', 'ENG_PS2j', 4, 'B', 'Sentence Creation', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of an animal that lives in the ocean (like a shark, a crab, or a dolphin). Tell me a sentence about what it does. Then write it down, sounding out any hard words as best you can.', 'Child orally composes and writes a sentence, utilizing phonetic encoding strategies for unknown words.', 'If they ask ''how do I spell...'', tell them ''Stretch the sounds and write what you hear.''', 'Show me a word you had to stretch out to spell. How did you figure it out?', '{"default":{"theme":"ocean animal"},"ug":{"theme":"lake animal (like a fish or hippo)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L4_C', 'ENG_PS2j', 4, 'C', 'Instructional Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'If your little sibling asks you ''how do you spell blanket?'', what steps would you tell them to follow so they can figure it out themselves?', 'Child articulates strategies: say it slowly, chop it into syllables, listen for each sound, write the letters for those sounds.', 'If they just say ''I would tell them b-l-a...'', remind them they are supposed to teach the *strategy*, not just give the answer.', 'Why is it better to listen to the sounds instead of just trying to memorize every word?', '{"default":{"concept":"how to spell an unknown word"},"ug":{"concept":"how to spell an unknown word"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_PS2j_L4_M', 'ENG_PS2j', 4, 'M', 'Milestone Production', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'We are making a list of three things you want to do this weekend. Say them out loud to me, then write them down. Don''t worry about perfect spelling—just stretch the sounds and write what you hear.', 'Child orally composes and independently writes a list, demonstrating functional phonetic spelling without freezing or constantly asking for help.', 'Do not correct during the task. The goal is confident, readable phonetic encoding.', 'Read your list back to me. Did you get all the sounds down?', '{"default":{"prompt":"three things you want to do this weekend"},"ug":{"prompt":"three things you want to do this weekend"}}', 0);

-- File: english_band_2_strand_2.json
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L1_A', 'ENG_RC2a', 1, 'A', 'Auditory & Visual Comprehension', 'None', NULL, NULL, NULL, NULL, 'Read the passage out loud. Ask: ''Who went to the market?''', 'Child correctly identifies the character who went to the market.', 'If incorrect, re-read the first sentence and ask the question again.', 'How do you know that person went to the market?', '{"default":{"character":"Alex","setting":"store"},"ug":{"character":"Amara","setting":"Kampala market"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L1_B', 'ENG_RC2a', 1, 'B', 'Physical Pointing', 'A printed copy of the passage', NULL, NULL, NULL, NULL, 'Read the passage out loud while pointing to the words. Ask: ''Point to the word that tells us what Amara bought.''', 'Child correctly points to the word ''mangoes''.', 'If incorrect, read the sentence again slowly and guide their finger.', 'What word did you point to?', '{"default":{"item":"apples"},"ug":{"item":"mangoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L1_C', 'ENG_RC2a', 1, 'C', 'Verbal Recall', 'None', NULL, NULL, NULL, NULL, 'Read the passage out loud. Ask: ''When did Amara go to the market? Morning or afternoon?''', 'Child correctly recalls the time of day from the text.', 'If incorrect, read the sentence mentioning the time again.', 'Did the story say she went in the morning or afternoon?', '{"default":{"time":"morning"},"ug":{"time":"morning"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L2_A', 'ENG_RC2a', 2, 'A', 'Written Answer - Who', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Tell me: Who is the main character? Say the answer in a full sentence, then write it.', 'Child writes a full sentence identifying the main character.', 'If incorrect or incomplete, remind them to use a full sentence and check the text.', 'Which sentence in the text tells you the character''s name?', '{"default":{"character":"Sam"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L2_B', 'ENG_RC2a', 2, 'B', 'Written Answer - What', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Tell me: What did Tendo plant? Say the answer, then write it.', 'Child writes a full sentence identifying what was planted.', 'If incorrect, prompt them to find the word ''planted'' in the text and read the rest of the sentence.', 'How did you know what he planted?', '{"default":{"item":"beans"},"ug":{"item":"matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L2_C', 'ENG_RC2a', 2, 'C', 'Written Answer - Where', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Tell me: Where did Tendo plant the seeds? Say the answer, then write it.', 'Child writes a full sentence identifying the location.', 'If incorrect, prompt them to scan the text for the place.', 'What words in the story told you where he was?', '{"default":{"place":"yard"},"ug":{"place":"garden by Lake Victoria"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L3_A', 'ENG_RC2a', 3, 'A', 'Detecting Factual Errors', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. I will say a sentence about it: ''Amara bought bananas at the market.'' Is that correct based on the story?', 'Child correctly identifies that the statement is false (she bought mangoes).', 'If they say it''s true, ask them to find the word ''bananas'' in the text.', 'What did she actually buy?', '{"default":{"item":"apples","wrong_item":"oranges"},"ug":{"item":"mangoes","wrong_item":"bananas"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L3_B', 'ENG_RC2a', 3, 'B', 'Correcting Statements', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read the passage. This sentence has a mistake: ''Tendo planted the seeds in the house.'' Tell me the mistake, and then write the corrected sentence.', 'Child correctly rewrites the sentence to state the seeds were planted in the garden.', 'If incorrect, prompt them to check where the story says the seeds were planted.', 'Why is ''in the house'' wrong?', '{"default":{"place":"yard","wrong_place":"house"},"ug":{"place":"garden","wrong_place":"house"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L3_C', 'ENG_RC2a', 3, 'C', 'Choosing the Correct Detail', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Which of these is true: A) Amara went to the market in the evening, or B) Amara went to the market in the morning?', 'Child selects the correct option based on the text.', 'If incorrect, ask them to find the word ''morning'' or ''evening'' in the text.', 'Show me exactly where the story says when she went.', '{"default":{"correct":"morning","incorrect":"evening"},"ug":{"correct":"morning","incorrect":"evening"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L4_A', 'ENG_RC2a', 4, 'A', 'Creating Questions', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read the passage. Now, write one ''Who'' question and one ''What'' question about the story to test me.', 'Child writes two valid literal comprehension questions.', 'If questions are not literal or not based on the text, guide them to ask about a specific detail.', 'Can you find the answer to your question right in the text?', '{"default":{"theme":"everyday life"},"ug":{"theme":"everyday life"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L4_B', 'ENG_RC2a', 4, 'B', 'Writing a Descriptive Sentence', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write a short sentence about what you ate for breakfast today. Make sure it tells ''what'' and ''when''.', 'Child writes a complete sentence containing both a ''what'' and a ''when'' detail.', 'If missing a detail, ask: ''Did you tell me what you ate? Did you tell me when?''', 'Which part of your sentence answers the question ''what''?', '{"default":{"meal":"breakfast"},"ug":{"meal":"breakfast (like chapati or porridge)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L4_C', 'ENG_RC2a', 4, 'C', 'Explaining Literal Details', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the passage to your sibling or me. Then, explain to us exactly what the main character did, using only facts from the story.', 'Child orally recounts the literal actions of the character without adding outside information.', 'If they add details not in the story, remind them to stick only to what the text says.', 'Is that detail written in the story, or did you guess it?', '{"default":{"character":"Alex"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2a_L4_M', 'ENG_RC2a', 4, 'M', 'Extracting Facts from a Note', 'Printed note, Paper, Pencil', NULL, NULL, NULL, NULL, 'Here is a note from your uncle. Read it. Then write down the answers to these questions: What time is he coming? What is he bringing?', 'Child reads the note and correctly extracts the time and the item.', 'Do not correct during the task. If they struggle significantly, return to Execute level literal comprehension.', 'How did you find the answers in the note?', '{"default":{"relative":"uncle","item":"book"},"ug":{"relative":"Uncle Musa","item":"groundnuts"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L1_A', 'ENG_RC2b', 1, 'A', 'Auditory Sequencing', 'None', NULL, NULL, NULL, NULL, 'Listen to this short story. ''First, Amara woke up. Next, she ate breakfast. Last, she walked to school.'' What did she do first?', 'Child correctly identifies that Amara woke up first.', 'If incorrect, emphasize the sequence words: First, Next, Last.', 'What word helped you know what happened at the beginning?', '{"default":{"sequence":"woke up, ate, walked"},"ug":{"sequence":"woke up, ate porridge, walked"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L1_B', 'ENG_RC2b', 1, 'B', 'Physical Sequencing', '3 picture cards or simple drawings representing the story events', NULL, NULL, NULL, NULL, 'I''m going to read a story. Here are three pictures showing what happens. Put the pictures in the correct order: beginning, middle, and end.', 'Child sequences the three pictures correctly.', 'If incorrect, re-read the story slowly and pause at each major event.', 'Why does this picture go in the middle?', '{"default":{"theme":"planting a seed"},"ug":{"theme":"planting matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L1_C', 'ENG_RC2b', 1, 'C', 'Verbal Retell Support', 'None', NULL, NULL, NULL, NULL, 'I will read a story about Tendo. When I finish, I want you to tell the story back to me. I''ll help by asking: ''What happened first?''', 'Child successfully recounts the first major event of the story.', 'If they struggle, provide the first event and ask what happened next.', 'Who was the story about and what did they do first?', '{"default":{"character":"Sam"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L2_A', 'ENG_RC2b', 2, 'A', 'Written Sequence - First', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. Tell me what happened first. Say it in a complete sentence, then write it.', 'Child writes a sentence describing the initial event.', 'If they describe the middle or end, remind them to look at the very beginning of the story.', 'How do you know this is what happened first?', '{"default":{"event":"woke up"},"ug":{"event":"woke up"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L2_B', 'ENG_RC2b', 2, 'B', 'Written Sequence - Next', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. Tell me what happened in the middle of the story, after the beginning. Say it, then write it.', 'Child writes a sentence describing the middle event.', 'If they describe the end, ask them what happened right after the first event.', 'What word in the story tells you this happened next?', '{"default":{"event":"ate breakfast"},"ug":{"event":"ate chapati"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L2_C', 'ENG_RC2b', 2, 'C', 'Written Sequence - Last', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. Tell me how the story ended. Say it, then write it down.', 'Child writes a sentence describing the concluding event.', 'If they miss the ending, ask them to read the very last sentence again.', 'How did the problem in the story get solved at the end?', '{"default":{"event":"went to school"},"ug":{"event":"walked to school"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L3_A', 'ENG_RC2b', 3, 'A', 'Detecting Out-of-Order Retell', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Now listen to my retell: ''First, Tendo found the ball. Then, he lost his ball. Last, he went home.'' Did I tell that in the right order?', 'Child identifies that the sequence is wrong.', 'If they say it''s right, have them look at the text to see which happened first: losing or finding.', 'Why doesn''t my order make sense?', '{"default":{"theme":"losing a ball"},"ug":{"theme":"losing a ball at the pitch"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L3_B', 'ENG_RC2b', 3, 'B', 'Identifying Missing Details', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the story. Here is my retell: ''Amara went to the market and then went home.'' What important middle detail did I leave out?', 'Child identifies the missing middle action (e.g., buying mangoes).', 'If they can''t find it, ask them to read the middle of the story again.', 'Why is that detail important to the story?', '{"default":{"character":"Alex","detail":"buying apples"},"ug":{"character":"Amara","detail":"buying mangoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L3_C', 'ENG_RC2b', 3, 'C', 'Correcting a Retell', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read the story. I wrote a retell, but I included something that didn''t happen: ''The dog barked at the cat, then chased a car.'' Tell me what is wrong, and write the correct sentence.', 'Child identifies the incorrect event and writes what actually happened.', 'If they struggle, ask them to check if a car is mentioned anywhere in the story.', 'Did the story say anything about a car?', '{"default":{"wrong_event":"chased a car"},"ug":{"wrong_event":"chased a car"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L4_A', 'ENG_RC2b', 4, 'A', 'Full Oral Retell', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the story silently. Then, put the paper face down and tell me the story in your own words. Make sure to include the beginning, middle, and end.', 'Child provides a complete oral retell including main characters, setting, and key sequence of events.', 'If they miss a major part, prompt them: ''What happened after...? / How did it start?''', 'Did you remember to tell me how the story ended?', '{"default":{"theme":"a day at the park"},"ug":{"theme":"a day at Lake Victoria"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L4_B', 'ENG_RC2b', 4, 'B', 'Written Summary', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read the story. Write a three-sentence summary. One sentence for the beginning, one for the middle, and one for the end. Tell me the sentences before you write.', 'Child writes three sequential sentences summarizing the story.', 'If they focus too much on minor details, ask: ''What was the most important thing that happened in the middle?''', 'Does your summary tell someone the whole story in just a few sentences?', '{"default":{"theme":"finding a lost item"},"ug":{"theme":"finding a lost goat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L4_C', 'ENG_RC2b', 4, 'C', 'Story Extension', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read the story. It tells us the beginning and middle. Think of an ending that makes sense. Tell it to me, then write the ending sentence.', 'Child creates a logical concluding sentence based on the story details.', 'If the ending doesn''t make sense, ask them to review what the problem in the story was.', 'How does your ending fix the problem in the story?', '{"default":{"theme":"cooking dinner"},"ug":{"theme":"cooking matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2b_L4_M', 'ENG_RC2b', 4, 'M', 'Message Relay', 'A printed paragraph of instructions', NULL, NULL, NULL, NULL, 'Here are instructions for what we need to do this afternoon. Read them. Then put the paper away and tell your sibling (or me) exactly what we need to do, in the right order.', 'Child accurately relays the sequential steps from the text from memory.', 'Do not correct during the task. If they fail significantly, review sequence words and memory retell.', 'Why is it important to tell the steps in the exact right order?', '{"default":{"theme":"cleaning the house"},"ug":{"theme":"sweeping the compound"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L1_A', 'ENG_RC2c', 1, 'A', 'Auditory Main Idea', 'None', NULL, NULL, NULL, NULL, 'I''m going to read a short passage. ''Birds build nests. They lay eggs in them. The eggs hatch into baby birds.'' Is this mostly about eggs, or mostly about how birds have babies?', 'Child correctly identifies the broader topic (how birds have babies/bird life cycle).', 'If they say eggs, ask: ''Does the first sentence talk about eggs?''', 'How do you know it''s not JUST about eggs?', '{"default":{"topic":"birds"},"ug":{"topic":"birds"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L1_B', 'ENG_RC2c', 1, 'B', 'Visual Categorization', 'Printed passage, 3 picture cards (one representing the main idea, two representing details)', NULL, NULL, NULL, NULL, 'Read this paragraph. Look at these three pictures. Point to the picture that shows what the WHOLE paragraph is mostly about, not just one little part.', 'Child selects the picture representing the main idea.', 'If they pick a detail picture, ask: ''Is the whole story about this one thing, or is it about the bigger picture?''', 'Why did you pick that picture?', '{"default":{"topic":"a farm"},"ug":{"topic":"a garden"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L1_C', 'ENG_RC2c', 1, 'C', 'Title Selection', 'None', NULL, NULL, NULL, NULL, 'Listen to this passage. ''Elephants are very big. They have long trunks. They use their trunks to drink water.'' Which is a better title: ''Drinking Water'' or ''All About Elephants''?', 'Child selects ''All About Elephants''.', 'If they select the detail title, explain that a good title covers everything in the story.', 'Why is ''Drinking Water'' not the best title?', '{"default":{"animal":"Elephants"},"ug":{"animal":"Elephants"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L2_A', 'ENG_RC2c', 2, 'A', 'Writing the Main Idea', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. What is this passage mostly about? Tell me your answer in one complete sentence, then write it down.', 'Child writes a sentence accurately capturing the main idea.', 'If they write a specific detail, prompt: ''That is one thing that happened. What is the big idea of the whole text?''', 'How do you know that is the main idea?', '{"default":{"topic":"weather"},"ug":{"topic":"the rainy season"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L2_B', 'ENG_RC2c', 2, 'B', 'Choosing and Writing a Title', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. It doesn''t have a title! Think of a title that tells what the story is mostly about. Tell it to me, then write it at the top of the paper.', 'Child provides a relevant title that reflects the main idea.', 'If the title is too narrow, ask them to make it broader to fit the whole story.', 'Why did you choose that title?', '{"default":{"topic":"baking a cake"},"ug":{"topic":"making chapati"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L2_C', 'ENG_RC2c', 2, 'C', 'Main Idea vs Detail', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Tell me the main idea. Now tell me one small detail. Write down the main idea sentence.', 'Child distinguishes between the main idea and a detail, and writes the main idea.', 'If they confuse them, explain that the main idea is like the umbrella, and the details are the people standing under it.', 'What makes a detail different from a main idea?', '{"default":{"topic":"dogs"},"ug":{"topic":"cows"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L3_A', 'ENG_RC2c', 3, 'A', 'Detecting a Poor Main Idea', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Someone said the main idea is: ''Amara has a red shirt.'' Is that the main idea, or just a small detail?', 'Child identifies that it is a small detail.', 'If they say it''s the main idea, ask: ''Is every sentence about her shirt?''', 'What is the passage ACTUALLY mostly about?', '{"default":{"detail":"red shirt"},"ug":{"detail":"red shirt"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L3_B', 'ENG_RC2c', 3, 'B', 'Fixing a Bad Title', 'Printed passage', NULL, NULL, NULL, NULL, 'Read this paragraph. The title is ''The Small Ant''. But the paragraph talks about lions, elephants, and zebras! What is wrong with the title, and what should it be?', 'Child recognizes the title doesn''t match the main idea and suggests a better one.', 'If they don''t know, ask them to list what animals are in the text.', 'Why does the title need to match the main idea?', '{"default":{"wrong_title":"The Small Ant"},"ug":{"wrong_title":"The Small Ant"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L3_C', 'ENG_RC2c', 3, 'C', 'Spotting the Off-Topic Sentence', 'Printed passage, Pencil', NULL, NULL, NULL, NULL, 'Read this paragraph. One of the sentences doesn''t belong because it''s not about the main idea. Find it and cross it out.', 'Child successfully identifies and crosses out the off-topic sentence.', 'If they cross out a valid supporting detail, help them define the main idea first.', 'Why did you cross that sentence out? What is the paragraph actually about?', '{"default":{"topic":"bicycles"},"ug":{"topic":"bicycles"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L4_A', 'ENG_RC2c', 4, 'A', 'Writing a Paragraph from a Main Idea', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will give you a main idea: ''Markets are very busy places.'' Tell me two details that support this. Now write a short paragraph with the main idea first, then your details.', 'Child composes a cohesive paragraph supporting the given main idea.', 'If their details go off-topic, remind them of the main idea sentence.', 'Read your paragraph. Do all your sentences talk about the market being busy?', '{"default":{"topic":"busy markets"},"ug":{"topic":"busy markets in Kampala"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L4_B', 'ENG_RC2c', 4, 'B', 'Teaching Main Idea', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this passage. Explain to me how you figure out what the main idea is. Write down your steps.', 'Child can articulate a strategy (e.g., look at the first sentence, see what words repeat) and write it down.', 'If they struggle to explain, ask them what they do in their head when asked ''what is it about?''.', 'Why is it helpful to find the main idea when you read?', '{"default":{"topic":"trees"},"ug":{"topic":"mango trees"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L4_C', 'ENG_RC2c', 4, 'C', 'Topic Sentence Creation', 'Printed paragraph missing its first sentence, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this paragraph. It is missing its very first sentence (the topic sentence). Think of a sentence that tells the main idea of all the other sentences. Say it, then write it.', 'Child creates an appropriate topic sentence that encapsulates the paragraph.', 'If the sentence is too specific, ask them to make it broader.', 'How did the other sentences help you decide what to write?', '{"default":{"topic":"sports"},"ug":{"topic":"football"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2c_L4_M', 'ENG_RC2c', 4, 'M', 'Summarizing a Letter', 'A printed letter, Paper, Pencil', NULL, NULL, NULL, NULL, 'Your cousin wrote you this letter. Read it. Then write one sentence to tell me what your cousin is trying to say in the letter.', 'Child reads the letter and synthesizes the main point into a single sentence.', 'Do not correct during the task. If they just list details, review Execute level tasks.', 'Does your sentence tell me the most important reason your cousin wrote the letter?', '{"default":{"relative":"cousin"},"ug":{"relative":"cousin"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L1_A', 'ENG_RC2d', 1, 'A', 'Auditory Detail Checking', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a main idea: ''Dogs are good pets.'' Which of these sentences is a detail that supports that idea: ''They can learn tricks'' or ''Cats sleep a lot''?', 'Child selects ''They can learn tricks''.', 'If they pick the cat detail, ask if that has anything to do with dogs being good pets.', 'Why does learning tricks make dogs good pets?', '{"default":{"topic":"pets"},"ug":{"topic":"pets"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L1_B', 'ENG_RC2d', 1, 'B', 'Physical Sorting of Details', 'Printed passage, 3 sentence strips (2 details from passage, 1 unrelated)', NULL, NULL, NULL, NULL, 'Read the passage. Here are three sentences. Two of them are details from the story that support the main idea. One is a trick. Sort them into ''Yes'' and ''No'' piles.', 'Child correctly sorts the supporting details into the Yes pile.', 'If they put the trick sentence in the Yes pile, ask them to find that information in the text.', 'Why did you put that sentence in the ''No'' pile?', '{"default":{"topic":"farming"},"ug":{"topic":"farming maize"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L1_C', 'ENG_RC2d', 1, 'C', 'Visual Highlighting', 'Printed passage, Crayon or marker', NULL, NULL, NULL, NULL, 'Read this paragraph. The main idea is the very first sentence: ''The market was very loud.'' Find one sentence that gives a detail proving it was loud, and color it in.', 'Child highlights a sentence describing noise (e.g., people shouting, cars honking).', 'If they highlight a sentence about what was sold, ask: ''Does that sentence tell us about the noise?''', 'How does the sentence you colored prove that the market was loud?', '{"default":{"topic":"loud market"},"ug":{"topic":"loud market in Kampala"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L2_A', 'ENG_RC2d', 2, 'A', 'Writing a Supporting Detail', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. The main idea is ''Elephants are strong.'' Find one detail in the text that shows how strong they are. Tell me the detail, then write it down.', 'Child writes a supporting detail extracted directly from the text.', 'If they make up a detail, redirect them to the text.', 'Show me where you found that detail in the story.', '{"default":{"animal":"Elephants"},"ug":{"animal":"Elephants"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L2_B', 'ENG_RC2d', 2, 'B', 'Providing Multiple Details', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. The author says ''Amara had a bad day.'' Find TWO details that tell us why her day was bad. Tell them to me, then write them.', 'Child writes two distinct supporting details from the passage.', 'If they only find one, prompt: ''What else went wrong for her?''', 'Do both of those details support the idea that her day was bad?', '{"default":{"character":"Alex"},"ug":{"character":"Amara"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L2_C', 'ENG_RC2d', 2, 'C', 'Matching Detail to Main Idea', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. It gives three reasons why washing hands is important. Write down the reason that talks about germs.', 'Child successfully locates and writes the specific supporting detail requested.', 'If they write a different reason, remind them we are looking specifically for the one about germs.', 'Why does the author think washing hands is important?', '{"default":{"topic":"washing hands"},"ug":{"topic":"washing hands before eating"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L3_A', 'ENG_RC2d', 3, 'A', 'Detecting Irrelevant Details', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the paragraph about why sleep is good for you. One of these sentences does not support the main idea: ''Sleep gives you energy'' or ''Beds can be made of wood''. Which one doesn''t belong?', 'Child identifies ''Beds can be made of wood'' as irrelevant to the main idea.', 'If they pick the wrong one, ask: ''Does knowing what a bed is made of tell us why sleep is good?''', 'Why does the sentence about the bed not belong with the others?', '{"default":{"topic":"sleep"},"ug":{"topic":"sleep"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L3_B', 'ENG_RC2d', 3, 'B', 'Fixing a Weak Argument', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this paragraph. The author wants to prove that ''Lions are dangerous''. But their supporting detail says ''Lions have fur.'' That doesn''t prove they are dangerous! Find a better detail in the text and write it down.', 'Child selects a detail like ''they have sharp teeth'' and writes it.', 'If they still pick a weak detail, ask: ''Does having fur make something dangerous? A rabbit has fur.''', 'How does your new detail do a better job of proving the main idea?', '{"default":{"animal":"Lions"},"ug":{"animal":"Lions"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L3_C', 'ENG_RC2d', 3, 'C', 'Evaluating Fact vs Inference', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the story. The main idea is ''Tendo was hungry.'' Did the author write the detail ''his stomach growled'', or did you just guess that because he was hungry?', 'Child accurately distinguishes whether the detail was explicitly stated in the text.', 'If they assume it was in the text without checking, tell them to point to the exact words.', 'Is it a supporting detail if the author didn''t actually write it down?', '{"default":{"character":"Sam"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L4_A', 'ENG_RC2d', 4, 'A', 'Brainstorming Details', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will give you a main idea: ''School is a busy place.'' Think of three details that prove this is true. Say them, then write them down.', 'Child generates three relevant supporting details independently.', 'If details are off-topic, repeat the main idea statement.', 'How do your details prove that school is busy?', '{"default":{"topic":"school"},"ug":{"topic":"school"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L4_B', 'ENG_RC2d', 4, 'B', 'Adding a Detail to a Text', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this paragraph about why eating fruit is healthy. It has two supporting details. Think of a third detail that could be added to make the paragraph stronger. Write it down.', 'Child composes a relevant supporting detail that fits the existing text.', 'If the detail contradicts the text, ask them to re-read what is already there.', 'Where would your new sentence fit best in the paragraph?', '{"default":{"topic":"fruit"},"ug":{"topic":"fruit like mangoes and jackfruit"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L4_C', 'ENG_RC2d', 4, 'C', 'Defending a Statement', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the story. I think the main character was very brave. You have to prove me right by finding three details in the text that show bravery. Tell them to me.', 'Child successfully orally extracts three supporting details to defend the premise.', 'If they struggle, ask: ''What did the character do when they saw the snake?''', 'Do you think the author wanted us to think the character was brave? Why?', '{"default":{"theme":"bravery"},"ug":{"theme":"bravery near the river"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2d_L4_M', 'ENG_RC2d', 4, 'M', 'Extracting Evidence', 'A printed advertisement or flyer, Paper, Pencil', NULL, NULL, NULL, NULL, 'Here is a flyer for a new bicycle. The flyer says this is the ''best bike ever.'' Read it and write down two reasons the flyer gives to prove it is the best.', 'Child extracts two supporting details used as evidence in the flyer.', 'Do not correct during the task. If they fail, review supporting details.', 'Did the flyer give good reasons, or just say it was the best without proving it?', '{"default":{"item":"bicycle"},"ug":{"item":"bicycle"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L1_A', 'ENG_RC2e', 1, 'A', 'Auditory Cause Identification', 'None', NULL, NULL, NULL, NULL, 'Listen to this sentence: ''Because it rained heavily, the road was muddy.'' What made the road muddy?', 'Child identifies the heavy rain as the cause.', 'If they say ''the road'', clarify: ''The road is muddy, but WHY did it get muddy?''', 'What word gives us a clue that we are hearing a cause?', '{"default":{"event":"rain and mud"},"ug":{"event":"heavy rain and muddy roads"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L1_B', 'ENG_RC2e', 1, 'B', 'Physical Matching (Cause to Effect)', 'Printed passage, Picture cards: one of rain, one of a puddle, one of sun, one of a dry plant', NULL, NULL, NULL, NULL, 'I''m going to read a story. When I''m done, match the picture of the ''cause'' (what happened first) to the picture of the ''effect'' (what happened because of it).', 'Child successfully matches cause and effect pairs.', 'If they match incorrectly, review the timeline of the story.', 'Why did the puddle form?', '{"default":{"theme":"weather"},"ug":{"theme":"weather"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L1_C', 'ENG_RC2e', 1, 'C', 'Verbal Effect Prediction', 'None', NULL, NULL, NULL, NULL, 'Listen to this part of a story: ''Tendo forgot to close the gate to the goat pen.'' What do you think the effect of that will be? What will happen next?', 'Child provides a logical prediction (e.g., the goats will get out).', 'If the prediction is illogical, ask what goats usually do when a gate is open.', 'Why would the goats leaving be an effect of the open gate?', '{"default":{"animal":"dog"},"ug":{"animal":"goats"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L2_A', 'ENG_RC2e', 2, 'A', 'Writing the Cause', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. The effect is that Amara was late for school. Find the sentence that tells us WHY she was late. Say it, then write it down.', 'Child identifies the cause and writes it accurately.', 'If they write that she was late, say: ''That is the effect. We need the reason why.''', 'What word did the author use to show the cause?', '{"default":{"character":"Alex","reason":"missed the bus"},"ug":{"character":"Amara","reason":"had to fetch water"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L2_B', 'ENG_RC2e', 2, 'B', 'Writing the Effect', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. The cause is that the boy dropped his glass of milk. What was the effect? What happened because he dropped it? Say it, then write it.', 'Child identifies the effect (e.g., the glass broke, milk spilled) and writes it.', 'If they write ''he dropped it'', remind them we are looking for the result.', 'What happened right after the glass fell?', '{"default":{"event":"dropping milk"},"ug":{"event":"dropping a cup of tea"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L2_C', 'ENG_RC2e', 2, 'C', 'Connecting Cause and Effect', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Write one sentence that has both the cause and the effect. Use the word ''because''. Tell me the sentence first.', 'Child constructs a cohesive ''because'' sentence linking the cause and effect found in the text.', 'If they put the effect after ''because'' (e.g., he was sad because he cried), guide them to swap the order.', 'Does your sentence explain WHY the thing happened?', '{"default":{"event":"lost a toy"},"ug":{"event":"lost a coin"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L3_A', 'ENG_RC2e', 3, 'A', 'Reversing Cause and Effect', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the story. Someone said, ''The floor got wet because the boy slipped.'' Wait, is that right? Did slipping cause the wet floor, or did the wet floor cause the slipping?', 'Child correctly identifies that the wet floor is the cause and slipping is the effect.', 'If they agree with the prompt, have them trace the events in order from the text.', 'Why does the order of cause and effect matter?', '{"default":{"event":"slipping on water"},"ug":{"event":"slipping in the mud"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L3_B', 'ENG_RC2e', 3, 'B', 'Spotting the Missing Cause', 'Printed passage', NULL, NULL, NULL, NULL, 'Read this paragraph. It says ''The plant died.'' But the author forgot to tell us WHY! Read it carefully—is the cause in the text, or is it missing?', 'Child recognizes that the text states an effect without providing the cause.', 'If they guess a cause (e.g., ''it didn''t get water''), tell them: ''You are smart to guess that, but did the author actually write it?''', 'How does a story feel when the author gives an effect but no cause?', '{"default":{"event":"plant dying"},"ug":{"event":"maize drying up"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L3_C', 'ENG_RC2e', 3, 'C', 'Evaluating ''So'' and ''Because''', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Look at this sentence: ''It was dark, because we turned on the lamp.'' That doesn''t make sense. Should the word be ''because'' or ''so''? Fix the sentence and write it.', 'Child identifies the incorrect conjunction and rewrites using ''so'' (or swaps the clauses).', 'If they struggle, explain that ''because'' introduces the cause, and ''so'' introduces the effect.', 'How does changing that one word fix the sentence?', '{"default":{"event":"dark and lamp"},"ug":{"event":"dark and lantern"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L4_A', 'ENG_RC2e', 4, 'A', 'Generating Causes', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will give you an effect: ''The dog barked loudly.'' Think of two different causes for why the dog might have barked. Write them down in full sentences.', 'Child generates two plausible causes for the given effect.', 'If the causes don''t make sense, prompt: ''What makes a dog bark in real life?''', 'Which of those causes do you think is more likely to happen?', '{"default":{"animal":"dog"},"ug":{"animal":"dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L4_B', 'ENG_RC2e', 4, 'B', 'Generating Effects', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I will give you a cause: ''The wind blew very hard.'' Think of an effect that could happen because of that. Tell it to me, then write a sentence using the word ''so''.', 'Child generates a plausible effect and uses ''so'' correctly in a sentence.', 'If they use ''because'', ask them to rephrase to start with the cause (The wind blew hard, so...).', 'What word did you use to connect the cause to the effect?', '{"default":{"cause":"strong wind"},"ug":{"cause":"strong wind before the rain"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L4_C', 'ENG_RC2e', 4, 'C', 'Explaining a Chain Reaction', 'Printed passage', NULL, NULL, NULL, NULL, 'Read this story. One thing causes another, which causes another! Tell me the chain reaction: what was the very first cause, and what was the very last effect?', 'Child traces a multi-step cause-and-effect chain from beginning to end.', 'If they miss a step, help them map it: ''A caused B, and B caused...?''', 'How did the first event lead all the way to the end of the story?', '{"default":{"theme":"domino effect"},"ug":{"theme":"domino effect at the market"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2e_L4_M', 'ENG_RC2e', 4, 'M', 'Analyzing Real-World Rules', 'A printed list of household rules, Paper, Pencil', NULL, NULL, NULL, NULL, 'Here is a list of rules for the house. Choose one rule. Write a sentence explaining what the rule is, and what the effect will be if you don''t follow it.', 'Child extracts a rule and logically infers or extracts the consequence (effect).', 'Do not correct during the task. If they fail to link cause and effect, review Execute level.', 'Why do rules usually have effects connected to them?', '{"default":{"theme":"house rules"},"ug":{"theme":"house rules"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L1_A', 'ENG_RC2f', 1, 'A', 'Auditory Emotion Identification', 'None', NULL, NULL, NULL, NULL, 'Listen to my voice when I read this: ''Oh no! I lost my favorite book!'' How does the character feel?', 'Child correctly identifies the feeling (sad, upset, worried).', 'If they say ''happy'', read it again emphasizing the distress in the tone.', 'What words helped you know how they felt?', '{"default":{"feeling":"sad"},"ug":{"feeling":"sad"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L1_B', 'ENG_RC2f', 1, 'B', 'Physical Emotion Matching', 'Printed passage, Cards with simple face drawings (happy, sad, angry, scared)', NULL, NULL, NULL, NULL, 'I''m going to read a short story about Tendo. When I finish, hold up the face card that shows how Tendo feels at the end of the story.', 'Child holds up the appropriate emotion card based on the text.', 'If incorrect, ask them what happened at the end of the story to make them choose that face.', 'Why did you choose the scared face? What happened in the story?', '{"default":{"character":"Sam","emotion":"scared"},"ug":{"character":"Tendo","emotion":"scared"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L1_C', 'ENG_RC2f', 1, 'C', 'Action to Trait Verbal Link', 'None', NULL, NULL, NULL, NULL, 'If a character shares their lunch with a friend who doesn''t have any, are they ''greedy'' or ''generous''?', 'Child correctly identifies ''generous'' (or kind).', 'If they don''t know the words, define them and ask again.', 'How does sharing lunch show that someone is generous?', '{"default":{"action":"sharing lunch"},"ug":{"action":"sharing roasted maize"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L2_A', 'ENG_RC2f', 2, 'A', 'Writing a Feeling', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. How did Amara feel when she won the race? Say the feeling in a sentence, then write it.', 'Child writes a sentence identifying the character''s emotion.', 'If they just write ''happy'', prompt them to write a full sentence.', 'What word in the story told you she was happy?', '{"default":{"character":"Alex","event":"won race"},"ug":{"character":"Amara","event":"won race"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L2_B', 'ENG_RC2f', 2, 'B', 'Writing Evidence for a Trait', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. The author says the boy is ''hardworking''. Find the sentence that PROVES he is hardworking. Say it, then write it down.', 'Child locates and writes the text evidence supporting the given trait.', 'If they write a detail unrelated to working hard, ask: ''Does that show he works hard?''', 'Why does sweeping the whole compound show that someone is hardworking?', '{"default":{"trait":"hardworking","action":"cleaning"},"ug":{"trait":"hardworking","action":"sweeping the compound"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L2_C', 'ENG_RC2f', 2, 'C', 'Tracking Changing Feelings', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. The character''s feelings change from the beginning to the end. Write one sentence about how they felt at the start, and one about how they felt at the end.', 'Child writes two sentences tracking the emotional shift.', 'If they miss the shift, ask: ''Did they feel the same way the whole time?''', 'What happened in the middle of the story to make their feelings change?', '{"default":{"shift":"sad to happy"},"ug":{"shift":"worried to relieved"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L3_A', 'ENG_RC2f', 3, 'A', 'Detecting Trait vs Feeling', 'Printed passage', NULL, NULL, NULL, NULL, 'Read this paragraph. Someone said, ''The character is feeling tall.'' Wait, ''tall'' is how they look, not how they feel. What is a word from the story that tells how they ACTUALLY feel?', 'Child differentiates between a physical trait and an emotion.', 'If they struggle, ask: ''Can you feel tall? Or do you feel happy/sad?''', 'What is the difference between how someone looks and how someone feels?', '{"default":{"physical":"tall","emotion":"proud"},"ug":{"physical":"tall","emotion":"proud"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L3_B', 'ENG_RC2f', 3, 'B', 'Evaluating Evidence', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read the story. A student wrote: ''Tendo is mean because he has a dog.'' Does having a dog prove someone is mean? Write a better sentence proving he is mean using evidence from the text.', 'Child rejects the illogical evidence and writes a sentence using valid text evidence.', 'If they can''t find evidence, ask them what Tendo did to the other children in the story.', 'Why is your evidence better than the first student''s evidence?', '{"default":{"character":"Sam","trait":"mean"},"ug":{"character":"Tendo","trait":"mean"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L3_C', 'ENG_RC2f', 3, 'C', 'Spotting Emotion Mismatch', 'Printed passage', NULL, NULL, NULL, NULL, 'Look at this sentence: ''Amara cried big tears because she was so excited.'' Does that make sense? Sometimes people cry when they are happy, but usually, tears mean something else. What word should probably replace ''excited''?', 'Child suggests an appropriate emotion like sad, upset, or hurt.', 'If they say ''happy'', explain the context usually implies sadness.', 'Why do authors need to make sure the actions match the feelings?', '{"default":{"character":"Alex","action":"cried"},"ug":{"character":"Amara","action":"cried"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L4_A', 'ENG_RC2f', 4, 'A', 'Writing Actions to Show Traits', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'I want you to invent a character who is ''lazy''. But you cannot use the word ''lazy'' in your sentence! Write a sentence showing them doing something that PROVES they are lazy.', 'Child writes a sentence describing an action indicative of laziness (e.g., sleeping all day).', 'If they use the word ''lazy'', remind them of the constraint.', 'How does your sentence ''show'' instead of ''tell''?', '{"default":{"trait":"lazy"},"ug":{"trait":"lazy"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L4_B', 'ENG_RC2f', 4, 'B', 'Writing Dialogue for Feelings', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of a character who is very angry. Write one sentence of exactly what they would say out loud. Use an exclamation mark!', 'Child writes dialogue reflecting anger, properly punctuated.', 'If the dialogue sounds happy or calm, ask: ''If you were mad, is that how you would say it?''', 'How does the exclamation mark help show the feeling?', '{"default":{"emotion":"angry"},"ug":{"emotion":"angry"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L4_C', 'ENG_RC2f', 4, 'C', 'Analyzing Parent-Provided Trait', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the story. I think the main character is ''curious'' (they like to know things). Do you agree or disagree? Explain why using events from the story.', 'Child defends or refutes the assigned trait using text evidence.', 'If they just say ''I agree'' without evidence, demand proof.', 'What is the strongest piece of evidence you have to support your opinion?', '{"default":{"trait":"curious"},"ug":{"trait":"curious"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2f_L4_M', 'ENG_RC2f', 4, 'M', 'Characterizing from a Letter', 'A printed letter, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this letter written by a child to their grandmother. Based on what they wrote, pick one word to describe the child (like kind, polite, selfish, or funny). Write the word, and write one sentence explaining why you picked it.', 'Child infers a character trait from the tone and content of a letter and supports it.', 'Do not correct during the task. If they fail to infer a trait, review Execute level.', 'Can you tell what kind of person someone is just by reading a letter they wrote?', '{"default":{"format":"letter to grandma"},"ug":{"format":"letter to Jajja (grandmother)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L1_A', 'ENG_RC2g', 1, 'A', 'Auditory Inference', 'None', NULL, NULL, NULL, NULL, 'Listen to this: ''Amara put on her boots, grabbed her umbrella, and ran outside.'' Did the story say it was raining?', 'Child correctly answers no, but infers that it is raining.', 'If they say yes, read it again and ask: ''Did I actually say the word rain?''', 'How do you know it''s raining even though the author didn''t say it?', '{"default":{"character":"Alex","items":"boots and umbrella"},"ug":{"character":"Amara","items":"gumboots and umbrella"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L1_B', 'ENG_RC2g', 1, 'B', 'Physical Clue Matching', 'Printed passage, Picture cards: one of a sunny beach, one of a snowy mountain, one of a rainy street', NULL, NULL, NULL, NULL, 'I''m going to read a story about what a boy packed in his suitcase: a heavy coat, mittens, and thick socks. Which picture shows where he is going?', 'Child selects the snowy mountain picture.', 'If they pick the beach, ask: ''Would you need a heavy coat at the beach?''', 'What clues in the story made you choose that picture?', '{"default":{"location":"snowy mountain"},"ug":{"location":"cold place like Kabale"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L1_C', 'ENG_RC2g', 1, 'C', 'Verbal Prediction from Clues', 'None', NULL, NULL, NULL, NULL, 'Listen to this: ''Tendo''s dog started digging a hole near the fence. Tendo yelled, "No, stop!"'' What do you think the dog is trying to do?', 'Child infers the dog is trying to escape or bury something.', 'If they guess randomly, ask: ''Why would a dog dig near a fence?''', 'What makes you think the dog is doing that?', '{"default":{"animal":"dog"},"ug":{"animal":"dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L2_A', 'ENG_RC2g', 2, 'A', 'Writing an Inference - Setting', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. It describes a place with lots of trees, birds singing, and a path made of dirt. The author never names the place. Where are they? Say it, then write it.', 'Child infers the setting (forest, woods, jungle) and writes it.', 'If they just list details, prompt: ''What do we call a place like that?''', 'What words helped you guess the setting?', '{"default":{"setting":"forest"},"ug":{"setting":"forest or village"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L2_B', 'ENG_RC2g', 2, 'B', 'Writing an Inference - Problem', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the passage. Amara is looking everywhere for her shoes. She is running late. What is her problem? The text doesn''t say ''Her problem is...'', so you have to figure it out. Write it down.', 'Child writes a sentence describing the problem (e.g., she lost her shoes and is late).', 'If they miss the urgency, point out ''running late''.', 'Why is losing her shoes a problem right now?', '{"default":{"character":"Alex","problem":"lost shoes"},"ug":{"character":"Amara","problem":"lost shoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L2_C', 'ENG_RC2g', 2, 'C', 'Explaining the Clues', 'Paper, Pencil, Printed passage', NULL, NULL, NULL, NULL, 'Read the story. The inference is ''The cake burned.'' Write down one clue from the story that proves this inference is true.', 'Child writes a detail like ''smoke coming from the oven'' or ''a bad smell''.', 'If they write ''the cake burned'', remind them we need the CLUE, not the inference.', 'Is your clue written directly in the story?', '{"default":{"theme":"burning food"},"ug":{"theme":"burning food (like chapati on a pan)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L3_A', 'ENG_RC2g', 3, 'A', 'Detecting a Bad Inference', 'Printed passage', NULL, NULL, NULL, NULL, 'Read this story about a boy who drops his ice cream. Someone inferred: ''He dropped it because he wanted to feed the ants.'' Is that a good inference or a silly guess?', 'Child identifies it as a silly guess/bad inference.', 'If they think it''s good, ask: ''Do people usually drop their treats on purpose to feed bugs?''', 'Why is that a bad inference?', '{"default":{"item":"ice cream"},"ug":{"item":"ice cream or mandazi"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L3_B', 'ENG_RC2g', 3, 'B', 'Fact vs Inference Sort', 'Printed passage', NULL, NULL, NULL, NULL, 'Read the story. Are these facts (written in the text) or inferences (figured out)? 1. ''Tendo was crying.'' 2. ''Tendo was sad because his toy broke.''', 'Child correctly identifies the first as a fact and the second as an inference (if the text only says he cried over a broken toy).', 'If they confuse them, ask: ''Did the author write the exact word sad?''', 'What is the difference between a fact and an inference?', '{"default":{"character":"Sam","emotion":"sad"},"ug":{"character":"Tendo","emotion":"sad"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L3_C', 'ENG_RC2g', 3, 'C', 'Finding the Missing Clue', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read the passage. I made an inference: ''The girl is tired.'' But the story only says she went to bed. What detail could the author add to make my inference stronger? Write it down.', 'Child suggests a clue like ''she yawned'' or ''her eyes were heavy''.', 'If they suggest ''she said I am tired'', remind them inferences rely on showing, not telling.', 'How does your new detail help prove she is tired?', '{"default":{"action":"yawning"},"ug":{"action":"yawning"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L4_A', 'ENG_RC2g', 4, 'A', 'Writing a Clue-Based Description', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write a short paragraph describing an animal (like a cat or dog) without ever naming the animal! Use clues about what it looks like and sounds like.', 'Child writes a descriptive paragraph that allows the reader to infer the animal.', 'If they name the animal, make them erase the name and replace it with ''the animal''.', 'Read your paragraph to me. Can I guess what animal it is from your clues?', '{"default":{"theme":"mystery animal"},"ug":{"theme":"mystery animal (like a goat or chicken)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L4_B', 'ENG_RC2g', 4, 'B', 'Making a Complex Inference', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this story about two friends talking. They aren''t looking at each other, and their arms are crossed. How do they feel about each other right now? Write it down and give one reason why.', 'Child infers the friends are angry/fighting and cites the body language as evidence.', 'If they think they are happy, have them cross their own arms and look away.', 'How does body language help us make inferences?', '{"default":{"relationship":"fighting friends"},"ug":{"relationship":"fighting friends"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L4_C', 'ENG_RC2g', 4, 'C', 'Explaining Inference', 'Printed passage', NULL, NULL, NULL, NULL, 'Explain to me what ''making an inference'' means. You can use the story we just read to help you explain.', 'Child articulates that an inference is using clues from the text plus what you already know to figure something out.', 'If they say ''guessing'', clarify the difference between a random guess and a smart guess using clues.', 'Why do authors sometimes make us infer things instead of just telling us?', '{"default":{"concept":"inference"},"ug":{"concept":"inference"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2g_L4_M', 'ENG_RC2g', 4, 'M', 'Inferring from a Real-World Scenario', 'A printed short dialogue, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this short conversation between a mother and child. Write down what you think just happened before they started talking. You have to figure it out from their words.', 'Child makes a logical inference about preceding events based on the dialogue.', 'Do not correct during the task. If they fail, review inference from clues.', 'What words did they say that gave you the biggest clue?', '{"default":{"theme":"spilled milk"},"ug":{"theme":"spilled tea or broken cup"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L1_A', 'ENG_RC2h', 1, 'A', 'Auditory Comparison (Same/Different)', 'None', NULL, NULL, NULL, NULL, 'Listen to Story 1: ''The dog chased the cat.'' Listen to Story 2: ''The dog chased the ball.'' Are these stories exactly the same? What is different?', 'Child identifies the difference (cat vs ball).', 'If they say yes, emphasize the final words of each sentence.', 'What is the same about both stories?', '{"default":{"theme":"chasing"},"ug":{"theme":"chasing"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L1_B', 'ENG_RC2h', 1, 'B', 'Physical Venn Diagram Sorting', 'Two printed passages, Two overlapping hoops or circles drawn on paper, Word cards (e.g., Dog, Cat, Both)', NULL, NULL, NULL, NULL, 'We have two short stories about pets. Place the ''Dog'' card in the circle for Story 1, the ''Cat'' card in Story 2''s circle. If something happens in BOTH stories, where does the card go?', 'Child places cards in the correct sections of the Venn diagram.', 'If they place ''Both'' in one circle, demonstrate the overlapping middle section.', 'Why does the middle part belong to both stories?', '{"default":{"theme":"pets"},"ug":{"theme":"animals (cows vs goats)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L1_C', 'ENG_RC2h', 1, 'C', 'Verbal Similarities', 'Two printed passages', NULL, NULL, NULL, NULL, 'I will read two short poems about rain. Tell me one thing that BOTH poems talk about.', 'Child identifies a common element (e.g., water, clouds, getting wet).', 'If they name something only in one poem, ask: ''Did the other poem talk about that?''', 'How are the two poems alike?', '{"default":{"theme":"rain"},"ug":{"theme":"rainy season"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L2_A', 'ENG_RC2h', 2, 'A', 'Writing a Similarity', 'Paper, Pencil, Two printed passages', NULL, NULL, NULL, NULL, 'Read Story A about a boy building a fort, and Story B about a girl building a treehouse. Write one sentence telling me how the stories are the SAME.', 'Child writes a sentence describing a shared element (e.g., they both built something).', 'If they write a difference, remind them we are looking for ''same''.', 'Show me where both stories talk about building.', '{"default":{"theme":"building"},"ug":{"theme":"building a toy car from wire"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L2_B', 'ENG_RC2h', 2, 'B', 'Writing a Difference', 'Paper, Pencil, Two printed passages', NULL, NULL, NULL, NULL, 'Read the two stories about the market again. Write one sentence telling me how they are DIFFERENT. (For example, ''In Story A..., but in Story B...'')', 'Child writes a sentence contrasting the two texts.', 'If they only describe one story, prompt: ''Tell me about the other story in the same sentence.''', 'What word did you use to show they are different? (e.g., but, however)', '{"default":{"theme":"market"},"ug":{"theme":"market (buying different things)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L2_C', 'ENG_RC2h', 2, 'C', 'Comparing Characters', 'Paper, Pencil, Two printed passages', NULL, NULL, NULL, NULL, 'Read the two stories. The main character in Story 1 is brave. Is the character in Story 2 brave, or something else? Write a sentence comparing the two characters.', 'Child writes a sentence comparing the traits of the two characters.', 'If they struggle, ask them to list what each character did.', 'How do their actions show they are different kinds of people?', '{"default":{"characters":"brave vs scared"},"ug":{"characters":"brave vs scared"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L3_A', 'ENG_RC2h', 3, 'A', 'Detecting False Comparisons', 'Two printed passages', NULL, NULL, NULL, NULL, 'Read the two passages about bears. Someone wrote: ''Both passages say bears eat fish.'' Check the texts. Is that true?', 'Child verifies if the claim is supported by both texts.', 'If they only check one text, remind them to check the other.', 'Why is it important to check both texts before saying they are the same?', '{"default":{"animal":"bears"},"ug":{"animal":"lions"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L3_B', 'ENG_RC2h', 3, 'B', 'Fixing a Venn Diagram Error', 'Two printed passages, A drawn Venn diagram with one error', NULL, NULL, NULL, NULL, 'Look at this Venn diagram comparing the two stories. I put ''has a dog'' in the middle (Both) section. But I made a mistake! Where should ''has a dog'' actually go?', 'Child identifies the error and moves the trait to the correct section.', 'If they don''t see the error, have them scan both stories for the word ''dog''.', 'Why doesn''t it belong in the middle?', '{"default":{"trait":"has a dog"},"ug":{"trait":"has a dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L3_C', 'ENG_RC2h', 3, 'C', 'Identifying the Better Source', 'Two printed passages', NULL, NULL, NULL, NULL, 'We need to learn how to plant seeds. Read Text A (a story about a boy planting seeds) and Text B (a list of instructions for planting). Which text is better if we want to learn HOW to do it?', 'Child selects the instructional text.', 'If they pick the story, ask: ''Does the story give us step-by-step directions?''', 'Why is Text B better for learning how to do something?', '{"default":{"topic":"planting seeds"},"ug":{"topic":"planting maize"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L4_A', 'ENG_RC2h', 4, 'A', 'Writing a Comparative Paragraph', 'Paper, Pencil, Two printed passages', NULL, NULL, NULL, NULL, 'Read the two passages about different types of houses. Write a short paragraph. Start by saying one way they are the same, then tell one way they are different.', 'Child writes a cohesive paragraph comparing and contrasting the texts.', 'If they struggle with structure, provide a frame: ''Both houses... However, House A...''', 'Did you include both a similarity and a difference?', '{"default":{"topic":"houses"},"ug":{"topic":"houses (brick vs mud/wattle)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L4_B', 'ENG_RC2h', 4, 'B', 'Generating a Companion Text', 'Printed passage, Paper, Pencil', NULL, NULL, NULL, NULL, 'Read this short story about a rainy day. Now, write your own very short story about a sunny day. Try to make your character do the opposite of the character in the first story.', 'Child writes a contrasting narrative based on a model text.', 'If their story is identical, emphasize doing the ''opposite''.', 'How is your sunny day story different from the rainy day story?', '{"default":{"theme":"weather opposite"},"ug":{"theme":"weather opposite"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L4_C', 'ENG_RC2h', 4, 'C', 'Explaining Author''s Purpose in Comparing', 'Two printed passages', NULL, NULL, NULL, NULL, 'Read the two texts about the same event (e.g., a football game). One is written by a fan of the winning team, one by a fan of the losing team. Explain to me why the two stories sound so different.', 'Child articulates that perspective changes how a story is told.', 'If they say ''one is lying'', explain perspective and feelings.', 'How do the authors'' feelings change the way they wrote their stories?', '{"default":{"theme":"sports game"},"ug":{"theme":"football match"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2h_L4_M', 'ENG_RC2h', 4, 'M', 'Comparing Real-World Options', 'Two printed menus or advertisements, Paper, Pencil', NULL, NULL, NULL, NULL, 'Here are flyers for two different schools (or camps). Read both. Write down one thing both schools have, and one thing that makes them different from each other.', 'Child extracts similarities and differences from functional texts.', 'Do not correct during the task. If they fail, review Venn diagrams and explicit comparison.', 'If you had to choose, which one would you pick based on the differences?', '{"default":{"theme":"camps"},"ug":{"theme":"schools"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L1_A', 'ENG_RC2i', 1, 'A', 'Auditory Feature Identification', 'A non-fiction book with a glossary/index', NULL, NULL, NULL, NULL, 'I''m going to read a word from the back of this book, and then tell you what page it is on. What part of the book am I looking at: the title, or the index?', 'Child identifies the index.', 'If they guess title, show them the front cover vs the back pages.', 'What does an index help us do?', '{"default":{"feature":"index"},"ug":{"feature":"index"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L1_B', 'ENG_RC2i', 1, 'B', 'Physical Scavenger Hunt', 'A non-fiction book or printed article with headings, bold words, and captions', NULL, NULL, NULL, NULL, 'Let''s go on a scavenger hunt in this book. Point to a bold word. Now point to a heading. Now point to a picture caption.', 'Child successfully locates the requested text features.', 'If they struggle, describe what the feature looks like (e.g., ''dark, thick letters'').', 'Why do you think the author made some words bold?', '{"default":{"features":"bold, heading, caption"},"ug":{"features":"bold, heading, caption"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L1_C', 'ENG_RC2i', 1, 'C', 'Verbal Feature Purpose', 'Printed article with a picture and caption', NULL, NULL, NULL, NULL, 'Look at this picture of a lion. Underneath, there is a small sentence that says ''Lions rest in the shade''. This is called a caption. What is the job of a caption?', 'Child explains that a caption tells about the picture.', 'If they don''t know, ask them to look at the picture and read the sentence again.', 'Could we understand the picture better with or without the caption?', '{"default":{"animal":"lion"},"ug":{"animal":"lion"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L2_A', 'ENG_RC2i', 2, 'A', 'Writing a Caption', 'Paper, Pencil, A picture or drawing', NULL, NULL, NULL, NULL, 'Look at this picture (e.g., a child riding a bike). It needs a caption! Tell me a sentence that explains the picture, then write it underneath.', 'Child composes and writes a relevant caption.', 'If the caption is unrelated, remind them it must describe exactly what is in the image.', 'How does your caption help someone understand the picture?', '{"default":{"picture":"riding a bike"},"ug":{"picture":"riding a bicycle with matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L2_B', 'ENG_RC2i', 2, 'B', 'Using a Heading', 'Paper, Pencil, Printed article with headings', NULL, NULL, NULL, NULL, 'Read the headings in this article. Which section would you read to learn what elephants eat? Write down the heading of that section.', 'Child identifies the correct heading (e.g., ''Diet'' or ''What They Eat'') and writes it.', 'If they write the whole paragraph, explain they only need the title of the section.', 'How do headings save us time when we are reading?', '{"default":{"animal":"elephants"},"ug":{"animal":"elephants"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L2_C', 'ENG_RC2i', 2, 'C', 'Extracting from a Table', 'Paper, Pencil, A simple printed table/chart', NULL, NULL, NULL, NULL, 'Look at this table showing how many books different children read. Find Amara''s name. How many books did she read? Write the number down.', 'Child successfully navigates the rows and columns to find the data.', 'If they pick the wrong number, trace the row from the name to the number with their finger.', 'Why is a table sometimes easier to read than a long paragraph?', '{"default":{"table":"books read"},"ug":{"table":"books read by local children"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L3_A', 'ENG_RC2i', 3, 'A', 'Detecting a Mismatched Caption', 'Printed picture with an incorrect caption', NULL, NULL, NULL, NULL, 'Look at this picture of a dog sleeping. The caption says: ''The dog is running fast.'' What is wrong, and how would you fix it?', 'Child identifies the mismatch and suggests a better caption.', 'If they don''t see the error, ask them to compare the action in the picture to the action in the words.', 'Why must the caption match the picture?', '{"default":{"picture":"sleeping dog"},"ug":{"picture":"sleeping dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L3_B', 'ENG_RC2i', 3, 'B', 'Spotting Heading Errors', 'Printed article with mixed-up headings', NULL, NULL, NULL, NULL, 'Look at this article. The heading says ''What They Eat'', but the paragraph is about where the animal lives! Which heading should be there instead?', 'Child identifies the error and suggests a better heading (e.g., ''Habitat'' or ''Where They Live'').', 'If they are confused, read the paragraph aloud and ask what the main idea is.', 'Why is a wrong heading confusing for a reader?', '{"default":{"heading":"What They Eat vs Habitat"},"ug":{"heading":"What They Eat vs Habitat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L3_C', 'ENG_RC2i', 3, 'C', 'Evaluating Text Formats', 'Printed paragraph vs printed list', NULL, NULL, NULL, NULL, 'Here is a recipe written as one long paragraph, and the same recipe written as a numbered list. Which one is easier to follow when you are cooking, and why?', 'Child selects the list and explains that it separates the steps clearly.', 'If they choose the paragraph, ask them to quickly find step 3 in both formats.', 'Why do authors use lists instead of paragraphs sometimes?', '{"default":{"format":"recipe"},"ug":{"format":"recipe for chapati"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L4_A', 'ENG_RC2i', 4, 'A', 'Formatting a Text', 'Paper, Pencil, A block of unformatted text', NULL, NULL, NULL, NULL, 'Here is a lot of information about lions. Rewrite it on your paper, but add a Title, at least one Heading, and underline the most important word to make it ''bold''.', 'Child structures the raw text into a formatted informational piece.', 'If they just copy it as a block, remind them of the features they need to add.', 'How does adding these features make your writing look better?', '{"default":{"animal":"lions"},"ug":{"animal":"lions"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L4_B', 'ENG_RC2i', 4, 'B', 'Creating a Table', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Ask three people in the house (or invent three people) what their favorite fruit is. Create a simple table or chart to show the answers. Make sure it has labels!', 'Child constructs a functional table organizing data.', 'If they just write a list, show them how to draw lines to make rows and columns.', 'How do the labels at the top of the table help us understand the data?', '{"default":{"data":"favorite fruit"},"ug":{"data":"favorite fruit (mango, jackfruit, banana)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L4_C', 'ENG_RC2i', 4, 'C', 'Teaching Text Features', 'A non-fiction book, Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to me why non-fiction books have things like tables of contents, glossaries, and indexes. Choose one of those features and write a sentence about how to use it.', 'Child articulates the purpose of navigational text features and writes a ''how-to'' sentence.', 'If they struggle, open the book to the index and ask them to find a specific word.', 'Do storybooks usually have an index? Why or why not?', '{"default":{"concept":"navigational features"},"ug":{"concept":"navigational features"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2i_L4_M', 'ENG_RC2i', 4, 'M', 'Navigating a Map/Diagram', 'A printed simple map or diagram with labels and a key, Paper, Pencil', NULL, NULL, NULL, NULL, 'Look at this map of a zoo. Use the map key to find where the lions are. Write down what is right next to the lions.', 'Child successfully uses the map key/labels to locate information and writes the answer.', 'Do not correct during the task. If they fail, review using diagrams and keys.', 'How did the map key help you find the answer?', '{"default":{"map":"zoo"},"ug":{"map":"wildlife park (Entebbe Zoo)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L1_A', 'ENG_RF2a', 1, 'A', 'Auditory Chunking', 'None', NULL, NULL, NULL, NULL, 'Listen to me read this sentence: ''The big dog... ran fast... to the park.'' Did I read it like a robot (word-by-word) or in chunks that make sense together?', 'Child identifies you read in chunks/groups of words.', 'If they say robot, demonstrate actual robot reading: ''The... big... dog... ran... fast...''', 'Why does it sound better when we group words together?', '{"default":{"animal":"dog","place":"park"},"ug":{"animal":"goat","place":"field"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L1_B', 'ENG_RF2a', 1, 'B', 'Physical Chunk Tracing', 'Printed sentence with phrase boundaries marked (e.g., with swoops or lines under chunks)', NULL, NULL, NULL, NULL, 'Run your finger under the first group of words as you read them: ''The little boy''. Pause. Now the next group: ''went to the store''.', 'Child successfully sweeps finger under phrases and pauses at boundaries.', 'If they stop at every word, hold their finger and guide the smooth sweep.', 'How does sweeping your finger help you read the words together?', '{"default":{"phrase":"went to the store"},"ug":{"phrase":"went to the market"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L1_C', 'ENG_RF2a', 1, 'C', 'Verbal Chunk Echoing', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a group of words that belong together. You echo them back smoothly. ''in the morning'' (wait for echo). ''we ate breakfast'' (wait for echo).', 'Child echoes the phrases smoothly without breaking them into choppy words.', 'If they chop it up, repeat it smoothly and ask them to sing it like a song.', 'Did ''in the morning'' sound like one big idea or three separate ideas?', '{"default":{"phrase":"ate breakfast"},"ug":{"phrase":"drank tea"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L2_A', 'ENG_RF2a', 2, 'A', 'Reading Marked Phrases', 'Printed passage with phrase boundaries marked (e.g., / or swoops)', NULL, NULL, NULL, NULL, 'Read this short paragraph out loud. Pause slightly wherever you see the slash mark (/). Try to make the words between the slashes flow together smoothly.', 'Child reads the passage, grouping words according to the provided boundaries.', 'If they ignore the marks, stop them and model the first sentence again.', 'Did pausing at the slashes make the story easier to understand?', '{"default":{"theme":"playing outside"},"ug":{"theme":"playing football"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L2_B', 'ENG_RF2a', 2, 'B', 'Marking and Reading Phrases', 'Paper, Pencil, Printed passage (unmarked)', NULL, NULL, NULL, NULL, 'Read this sentence silently. Take your pencil and draw a slash (/) where you think a natural pause should go, separating the ''who'' from the ''what they did''. Then read it aloud.', 'Child correctly identifies phrase boundaries (e.g., subject/predicate or prepositional phrases) and reads it smoothly.', 'If they mark every word, remind them we are looking for groups of words that belong together.', 'Why did you put the pause right there?', '{"default":{"theme":"eating lunch"},"ug":{"theme":"eating lunch (posho and beans)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L2_C', 'ENG_RF2a', 2, 'C', 'Reading Fluency Practice', 'Printed passage', NULL, NULL, NULL, NULL, 'Read this paragraph out loud. Focus on reading in phrases, not word-by-word. Think about how you would say it if you were just talking to me.', 'Child reads the passage with conversational phrasing, abandoning word-by-word reading.', 'If choppy, have them read the same sentence three times until it smooths out.', 'Did it sound more like reading or more like talking?', '{"default":{"theme":"a windy day"},"ug":{"theme":"a rainy afternoon"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L3_A', 'ENG_RF2a', 3, 'A', 'Detecting Choppy Reading', 'Printed passage', NULL, NULL, NULL, NULL, 'Listen to me read this sentence: ''The. Cat. Sat. On. The. Mat.'' Did I read that well? What did I do wrong?', 'Child identifies that you read word-by-word (choppy) instead of in phrases.', 'If they say it was good, ask: ''Is that how we talk?''', 'How should I read it instead?', '{"default":{"animal":"Cat"},"ug":{"animal":"Cat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L3_B', 'ENG_RF2a', 3, 'B', 'Detecting Wrong Phrasing', 'Printed passage', NULL, NULL, NULL, NULL, 'Listen to me read this: ''The boy walked to / the store to buy / some milk.'' Did my pauses sound natural, or did I break up groups of words that belong together?', 'Child identifies that the pauses were unnatural (splitting prepositional phrases or verb phrases awkwardly).', 'If they think it''s fine, read it again with proper phrasing and ask which sounds better.', 'Where should the pauses actually go?', '{"default":{"item":"milk"},"ug":{"item":"milk"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L3_C', 'ENG_RF2a', 3, 'C', 'Choosing the Better Reading', 'Printed passage', NULL, NULL, NULL, NULL, 'I will read this sentence two ways. Way 1: ''The dog / ran fast / to the house.'' Way 2: ''The dog ran / fast to the / house.'' Which way made the story easier to understand?', 'Child selects Way 1, recognizing appropriate phrasing.', 'If they pick 2, ask them what ''fast to the'' means by itself.', 'Why is it confusing when we pause in the middle of an idea?', '{"default":{"animal":"dog"},"ug":{"animal":"goat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L4_A', 'ENG_RF2a', 4, 'A', 'Directing a Reader', 'Printed passage, Pencil', NULL, NULL, NULL, NULL, 'You are the director! Take this paragraph and draw slashes where I should pause. I will read it exactly how you mark it.', 'Child accurately marks phrase boundaries. Parent reads it as marked. Child evaluates.', 'If they put slashes in weird places, read it exactly as marked so they hear the awkwardness, then let them fix it.', 'How did my reading sound based on your marks?', '{"default":{"theme":"building a snowman"},"ug":{"theme":"building a fire"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L4_B', 'ENG_RF2a', 4, 'B', 'Expressive Oral Reading', 'A favorite book or printed passage', NULL, NULL, NULL, NULL, 'Pick a page from this book. Practice reading it silently first, focusing on grouping words. Then, read it out loud to me like you are a storyteller on the radio.', 'Child prepares and delivers a fluent, phrased reading of the text.', 'If still choppy, select a shorter sentence and have them practice it repeatedly.', 'How did practicing silently help you read it out loud?', '{"default":{"format":"book page"},"ug":{"format":"book page"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L4_C', 'ENG_RF2a', 4, 'C', 'Teaching Phrasing', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to someone younger what ''reading in chunks'' means. Why is it important? Write one sentence showing a bad way to read, and one sentence explaining the good way.', 'Child articulates the concept of phrasing and its impact on comprehension/fluency.', 'If they struggle, ask: ''If you read every word like a robot, do you remember what the story is about?''', 'Why does reading smoothly help our brain understand the story better?', '{"default":{"concept":"phrasing"},"ug":{"concept":"phrasing"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2a_L4_M', 'ENG_RF2a', 4, 'M', 'Cold Read Fluency', 'A new, unseen printed passage, Audio recording device (optional)', NULL, NULL, NULL, NULL, 'Here is a story you haven''t seen before. Read it out loud to me. Do your best to make it sound smooth and interesting, not choppy.', 'Child demonstrates generalized fluency and phrasing on a cold read.', 'Do not correct during the reading. Note areas of choppiness for future practice. If highly choppy, return to Execute level.', 'Did you feel like you were grouping words together as you read?', '{"default":{"theme":"a surprise party"},"ug":{"theme":"a surprise visitor"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L1_A', 'ENG_RF2b', 1, 'A', 'Auditory Rate Identification', 'None', NULL, NULL, NULL, NULL, 'Listen to me read this sentence. (Read very fast). Now listen again. (Read very slow). Which way was easier to understand and why?', 'Child identifies that neither extreme is good; a middle pace is best.', 'If they prefer the fast one, ask them to repeat what you just said.', 'Why is reading too fast a problem?', '{"default":{"speed":"fast vs slow"},"ug":{"speed":"fast vs slow"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L1_B', 'ENG_RF2b', 1, 'B', 'Physical Pacing', 'Printed passage', NULL, NULL, NULL, NULL, 'I am going to read this passage at a ''just right'' walking pace. Try to point to the words exactly as I say them, not too fast, not too slow.', 'Child tracks the text accurately at a fluent conversational pace.', 'If they lag behind or speed ahead, guide their finger to match your voice.', 'Did we move our fingers like a race car, or like someone taking a walk?', '{"default":{"pace":"walking"},"ug":{"pace":"walking"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L1_C', 'ENG_RF2b', 1, 'C', 'Verbal Rate Check', 'None', NULL, NULL, NULL, NULL, 'If I read so fast that I skip words and get out of breath, am I reading at a good rate? What if I read so slow I forget what the beginning of the sentence was about?', 'Child articulates that both extremes hinder comprehension.', 'If they don''t know, explain the concept of a ''talking speed''.', 'What speed should we aim for when reading out loud?', '{"default":{"concept":"reading speed"},"ug":{"concept":"reading speed"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L2_A', 'ENG_RF2b', 2, 'A', 'Timed Repeated Reading', 'Printed passage, Timer/Stopwatch', NULL, NULL, NULL, NULL, 'Read this paragraph out loud. I will time you. Don''t rush and make mistakes, just read smoothly. Ready? Go.', 'Child reads the passage. Note the time. (Goal is age-appropriate WPM, usually 60-90 WPM in Band 2).', 'If they read too fast and make many errors, say: ''This isn''t a race. Accuracy is more important than speed.''', 'Did you feel rushed, or did it feel like a comfortable speed?', '{"default":{"theme":"baking"},"ug":{"theme":"cooking"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L2_B', 'ENG_RF2b', 2, 'B', 'Beat the Timer (Accuracy Focus)', 'Printed passage, Timer/Stopwatch', NULL, NULL, NULL, NULL, 'You read that paragraph in 45 seconds last time. Let''s read it again. Try to beat your time, BUT if you make a mistake, you have to go back and fix it.', 'Child reads the passage slightly faster due to familiarity, maintaining accuracy.', 'If they speed read and ignore errors, stop the timer. ''We have to read it right first.''', 'Why was it easier to read it faster the second time?', '{"default":{"theme":"baking"},"ug":{"theme":"cooking"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L2_C', 'ENG_RF2b', 2, 'C', 'Reading with a Metronome/Pacer', 'Printed passage', NULL, NULL, NULL, NULL, 'I will tap my finger on the table in a steady beat. Try to read the words to match my steady beat. Don''t speed up!', 'Child maintains a steady reading rate without rushing or dragging.', 'If they ignore the beat, stop and have them just say ''da da da'' to the beat first.', 'How does keeping a steady beat help your reading sound better?', '{"default":{"theme":"a long walk"},"ug":{"theme":"walking to school"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L3_A', 'ENG_RF2b', 3, 'A', 'Evaluating Reader Rate', 'Printed passage', NULL, NULL, NULL, NULL, 'Listen to me read this paragraph. (Read it slightly too fast, slurring some words). Give me advice: Should I speed up, slow down, or keep the same speed?', 'Child identifies you are reading too fast and advises slowing down.', 'If they say it was good, ask: ''Could you understand every word I said?''', 'Why is reading that fast a bad idea?', '{"default":{"passage":"parent reads fast"},"ug":{"passage":"parent reads fast"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L3_B', 'ENG_RF2b', 3, 'B', 'The Accuracy Trade-off', 'Printed passage', NULL, NULL, NULL, NULL, 'If a student reads 100 words in a minute but gets 20 of them wrong, and another student reads 60 words in a minute and gets all of them right, who is the better reader?', 'Child identifies the slower, accurate reader as better.', 'If they pick the fast one, explain that reading is about understanding, not just speed.', 'Why doesn''t speed matter if you get the words wrong?', '{"default":{"concept":"accuracy vs speed"},"ug":{"concept":"accuracy vs speed"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L3_C', 'ENG_RF2b', 3, 'C', 'Identifying Punctuation Pauses', 'Printed passage', NULL, NULL, NULL, NULL, 'Read this sentence. It has commas and a full stop. When you read fast, you might ignore them. Read it at a good rate, and make sure I hear you pause at the punctuation.', 'Child reads at a controlled rate, observing punctuation boundaries.', 'If they barrel through commas, have them read it again and clap at every comma.', 'How does punctuation control how fast we read?', '{"default":{"punctuation":"commas and periods"},"ug":{"punctuation":"commas and full stops"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L4_A', 'ENG_RF2b', 4, 'A', 'Setting the Pace', 'A printed poem or rhythmic text', NULL, NULL, NULL, NULL, 'You are in charge of how fast we read this poem together. Read it out loud, and I will try to match your exact speed. Make sure you pick a good ''talking speed.''', 'Child sets and maintains an appropriate reading rate while reading chorally with the parent.', 'If they read too fast, the parent should struggle to keep up intentionally to demonstrate.', 'Was it hard to keep the same speed the whole time?', '{"default":{"theme":"poem"},"ug":{"theme":"poem"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L4_B', 'ENG_RF2b', 4, 'B', 'Adjusting Rate for Purpose', 'Two short printed sentences (one urgent, one sleepy)', NULL, NULL, NULL, NULL, 'Look at sentence A: ''Quick, the bus is leaving!'' Look at sentence B: ''The old turtle slowly went to sleep.'' Read them out loud. Should you read them at the exact same speed?', 'Child reads sentence A faster and sentence B slower, adjusting rate for meaning.', 'If they read both identically, ask them what is happening in each sentence.', 'Why did you change your speed for the second sentence?', '{"default":{"theme":"urgent vs slow"},"ug":{"theme":"urgent vs slow"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L4_C', 'ENG_RF2b', 4, 'C', 'Self-Evaluation', 'Printed passage, Timer', NULL, NULL, NULL, NULL, 'Read this paragraph. Time yourself. When you finish, tell me: Did I read too fast, too slow, or just right? Did I understand what I read?', 'Child reads, self-monitors their rate, and evaluates their comprehension.', 'If their self-evaluation doesn''t match reality (e.g., they rushed but say it was perfect), provide gentle feedback.', 'How do you know if you are reading at the right speed?', '{"default":{"theme":"a busy day"},"ug":{"theme":"a busy day"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2b_L4_M', 'ENG_RF2b', 4, 'M', 'Reading a Story to an Audience', 'A familiar storybook or printed story', NULL, NULL, NULL, NULL, 'I want you to read this story to your younger sibling (or a stuffed animal/pet). Read it at a speed that helps them understand and enjoy the story.', 'Child demonstrates appropriate reading rate and fluency in an authentic read-aloud context.', 'Do not correct during the reading. Evaluate if the rate facilitated comprehension for the audience.', 'Did you have to slow down so they could understand the story better?', '{"default":{"audience":"sibling"},"ug":{"audience":"sibling"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L1_A', 'ENG_RF2c', 1, 'A', 'Auditory Emotion Matching', 'None', NULL, NULL, NULL, NULL, 'Listen to me say this: ''I can''t believe we are going to the zoo!'' Did my voice go up or down at the end? Did I sound bored or excited?', 'Child identifies the pitch going up and the excited tone.', 'If they say bored, say it again completely flat, then contrast with the excited version.', 'How does my voice change when I''m excited?', '{"default":{"theme":"zoo"},"ug":{"theme":"wildlife park"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L1_B', 'ENG_RF2c', 1, 'B', 'Physical Punctuation Action', 'None', NULL, NULL, NULL, NULL, 'When I read a sentence that ends in a question mark (?), shrug your shoulders. When it ends in an exclamation mark (!), throw your hands up. ''Where is the dog?'' (wait). ''There he is!'' (wait).', 'Child physically responds to the auditory cues of different sentence types.', 'If they miss the cue, explain that our voice goes up for a question and gets loud/strong for an exclamation.', 'How does your voice tell someone there is a question mark at the end of the sentence?', '{"default":{"animal":"dog"},"ug":{"animal":"goat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L1_C', 'ENG_RF2c', 1, 'C', 'Verbal Echo with Expression', 'None', NULL, NULL, NULL, NULL, 'I''m going to say a sentence in a grumpy voice. You echo it back in the exact same grumpy voice. ''I don''t want to eat my vegetables.''', 'Child accurately mimics the tone and inflection.', 'If they say it normally, exaggerate the grumpiness and ask them to act like an actor.', 'How did making your voice grumpy change the meaning of the words?', '{"default":{"food":"vegetables"},"ug":{"food":"cabbage"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L2_A', 'ENG_RF2c', 2, 'A', 'Reading with Punctuation', 'Printed sentences with varied end punctuation', NULL, NULL, NULL, NULL, 'Read these three sentences out loud. Make sure your voice tells me which one has a full stop, which has a question mark, and which has an exclamation mark.', 'Child reads the sentences with appropriate inflection (flat, rising pitch, strong emphasis).', 'If they read them all the same, model the difference and have them repeat.', 'How did your voice change for the question?', '{"default":{"sentences":"The cat is here. Is the cat here? The cat is here!"},"ug":{"sentences":"The cat is here. Is the cat here? The cat is here!"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L2_B', 'ENG_RF2c', 2, 'B', 'Emphasizing Key Words', 'Printed sentence with one word bolded', NULL, NULL, NULL, NULL, 'Read this sentence, but make your voice extra strong on the bold word: ''I did **not** eat the last cookie.'' Now read it again emphasizing a different word: ''**I** did not eat the last cookie.''', 'Child successfully shifts emphasis to change the nuance of the sentence.', 'If they struggle, say it for them and ask them to copy.', 'How does changing the strong word change the meaning of the sentence?', '{"default":{"food":"cookie"},"ug":{"food":"mandazi"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L2_C', 'ENG_RF2c', 2, 'C', 'Character Voices', 'Printed dialogue passage', NULL, NULL, NULL, NULL, 'Read this story where a big bear is talking to a tiny mouse. Use a deep voice for the bear, and a squeaky voice for the mouse.', 'Child distinguishes speakers by altering pitch and tone.', 'If they use their normal voice, remind them: ''You are an actor right now. Be the bear!''', 'How do character voices make a story more fun to listen to?', '{"default":{"characters":"bear and mouse"},"ug":{"characters":"lion and mouse"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L3_A', 'ENG_RF2c', 3, 'A', 'Detecting Mismatched Tone', 'Printed passage', NULL, NULL, NULL, NULL, 'Listen to me read this scary part of a story. (Read it in a very happy, cheerful voice). Did my voice match what was happening in the story?', 'Child identifies the mismatch between content and tone.', 'If they say it was fine, ask: ''If something scary is happening, do people sound happy?''', 'How should I have used my voice instead?', '{"default":{"theme":"scary story"},"ug":{"theme":"scary story"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L3_B', 'ENG_RF2c', 3, 'B', 'Fixing the Question Pitch', 'Printed sentence', NULL, NULL, NULL, NULL, 'I''m going to read this question: ''Where are my shoes.'' (Read it with a flat, falling pitch like a statement). What did I forget to do with my voice at the end?', 'Child identifies that the pitch should rise at the end of a question.', 'If they don''t know, model the correct rising pitch.', 'Can you read it the right way?', '{"default":{"item":"shoes"},"ug":{"item":"shoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L3_C', 'ENG_RF2c', 3, 'C', 'Choosing the Right Emphasis', 'Printed sentence', NULL, NULL, NULL, NULL, 'Look at this sentence: ''That is a huge dog!'' Which word should we say the loudest to make it sound right? Huge or dog?', 'Child selects ''huge'' to emphasize the descriptive element.', 'If they select ''dog'', read it both ways and ask which sounds more natural.', 'Why does emphasizing ''huge'' make the sentence better?', '{"default":{"animal":"dog","adjective":"huge"},"ug":{"animal":"dog","adjective":"huge"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L4_A', 'ENG_RF2c', 4, 'A', 'Marking Text for Expression', 'Printed passage, Highlighter or Pencil', NULL, NULL, NULL, NULL, 'Read this paragraph silently. Think about how it should sound. Underline two words that you think should be read LOUDLY or with strong feeling. Then read it out loud to me.', 'Child independently selects words for emphasis and executes the reading accordingly.', 'If they underline random words like ''the'', ask: ''Does emphasizing *the* change the meaning?''', 'Why did you choose to make those specific words strong?', '{"default":{"theme":"a big surprise"},"ug":{"theme":"a big surprise"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L4_B', 'ENG_RF2c', 4, 'B', 'Writing Dialogue with Emotion Cues', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write a short sentence of dialogue where someone is whispering because they are hiding. Then write a sentence where they are shouting because they are angry.', 'Child composes sentences that implicitly demand specific prosodic delivery.', 'If the content doesn''t match the emotion, prompt them to think about what people say when hiding/angry.', 'Read your sentences out loud to me using the right voices.', '{"default":{"emotions":"whispering vs shouting"},"ug":{"emotions":"whispering vs shouting"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L4_C', 'ENG_RF2c', 4, 'C', 'Explaining Punctuation Power', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Explain to me why punctuation marks are like road signs for our voice when we read out loud. Give an example.', 'Child articulates that punctuation dictates stops, pauses, and pitch changes.', 'If they struggle, ask: ''What happens if we ignore a stop sign on the road? What if we ignore a full stop in a book?''', 'How does a question mark tell your voice what to do?', '{"default":{"concept":"punctuation as signals"},"ug":{"concept":"punctuation as signals"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RF2c_L4_M', 'ENG_RF2c', 4, 'M', 'Radio Play Reading', 'A printed script or dialogue-heavy passage', NULL, NULL, NULL, NULL, 'We are going to do a radio play! You read this part, and I''ll read this part. You have to use your voice to show exactly how your character feels.', 'Child reads their part fluently, integrating appropriate phrasing, rate, and expressive prosody.', 'Do not correct during the performance. If flat and robotic, review Execute level tasks.', 'Did you feel like you were acting with your voice?', '{"default":{"format":"script"},"ug":{"format":"script"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L1_A', 'ENG_RC2j', 1, 'A', 'Auditory Rhyme Identification', 'None', NULL, NULL, NULL, NULL, 'Listen to this short poem: ''The fat cat / sat on the mat.'' Which words rhyme? What sound do they all have at the end?', 'Child identifies cat, sat, mat and the /at/ sound.', 'If they don''t hear it, emphasize the ends of the words: c-AT, s-AT.', 'Why do poems often use rhyming words?', '{"default":{"words":"cat, sat, mat"},"ug":{"words":"cat, sat, mat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L1_B', 'ENG_RC2j', 1, 'B', 'Physical Rhythm Clapping', 'None', NULL, NULL, NULL, NULL, 'I am going to say a rhyme. I want you to clap on the strong beats with me. ''Hickory dickory dock, the mouse ran up the clock.''', 'Child claps along with the metrical rhythm of the text.', 'If they clap on every syllable, guide their hands to only clap the stressed beats.', 'Did that sound like a regular story, or more like a song?', '{"default":{"poem":"nursery rhyme"},"ug":{"poem":"nursery rhyme or local chant"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L1_C', 'ENG_RC2j', 1, 'C', 'Visual Line Break Awareness', 'A printed poem and a printed paragraph', NULL, NULL, NULL, NULL, 'Look at this poem, and look at this regular story paragraph. How do they look different on the page? Look at where the lines end.', 'Child identifies that poems have short lines and don''t go all the way to the edge of the page.', 'If they don''t see it, trace the ragged right edge of the poem vs the blocky paragraph.', 'Why do you think the poet chopped the lines up like that?', '{"default":{"format":"poem vs prose"},"ug":{"format":"poem vs prose"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L2_A', 'ENG_RC2j', 2, 'A', 'Completing a Rhyme', 'Paper, Pencil, Printed poem missing the last word', NULL, NULL, NULL, NULL, 'Read this poem. The very last word is missing. Think of a word that makes sense AND rhymes with the line above it. Tell it to me, then write it in the blank.', 'Child orally provides and writes a valid rhyming word that fits the context.', 'If it doesn''t rhyme, ask: ''What word does it need to sound like?'' If it doesn''t make sense, ask: ''Does that fit the story?''', 'How did you know that was the right word to use?', '{"default":{"rhyme":"sun / fun"},"ug":{"rhyme":"sun / fun"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L2_B', 'ENG_RC2j', 2, 'B', 'Writing Rhyming Pairs', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of a word that rhymes with ''tree''. Now write a very short two-line poem using those two words at the ends of the lines. Say it out loud first.', 'Child composes and writes a simple rhyming couplet.', 'If the lines don''t make sense together, prompt them to connect the ideas.', 'Read your poem out loud. Does it have a rhythm to it?', '{"default":{"word":"tree"},"ug":{"word":"tree"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L2_C', 'ENG_RC2j', 2, 'C', 'Reading with Rhythm', 'Printed poem', NULL, NULL, NULL, NULL, 'Read this poem out loud. Pay attention to the line breaks. Pause slightly at the end of each line, even if there isn''t a full stop, so we can hear the rhythm.', 'Child reads the poem, honoring line breaks and emphasizing the meter.', 'If they read it like prose (running lines together), model the rhythmic pauses and have them try again.', 'How does pausing at the end of the line help the poem sound better?', '{"default":{"theme":"stars"},"ug":{"theme":"stars"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L3_A', 'ENG_RC2j', 3, 'A', 'Detecting a Broken Rhyme', 'Printed poem', NULL, NULL, NULL, NULL, 'Listen to this: ''Roses are red, violets are blue, sugar is sweet, and I like orange.'' Does that sound like a good poem? What went wrong at the end?', 'Child identifies that the rhyming pattern was broken.', 'If they don''t hear it, ask: ''Does orange rhyme with blue?''', 'What word could we use instead to fix the rhyme?', '{"default":{"broken_rhyme":"blue / orange"},"ug":{"broken_rhyme":"blue / orange"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L3_B', 'ENG_RC2j', 3, 'B', 'Detecting Broken Rhythm', 'Printed poem', NULL, NULL, NULL, NULL, 'Listen: ''Twinkle twinkle little star, how I wonder what you are up in the sky so very high.'' Did I read that with the right beat, or did I mess up the rhythm?', 'Child identifies that running the lines together ruined the song''s meter/rhythm.', 'If they think it''s fine, sing it correctly and ask them to compare.', 'Why does rhythm matter in a poem or song?', '{"default":{"poem":"Twinkle Twinkle"},"ug":{"poem":"Twinkle Twinkle"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L3_C', 'ENG_RC2j', 3, 'C', 'Identifying Sensory Language', 'Printed poem', NULL, NULL, NULL, NULL, 'Poems often use words that paint a picture in your mind. Look at this poem. Find one phrase that helps you ''see'' or ''hear'' what the poet is talking about.', 'Child locates descriptive, sensory language within the poetic text.', 'If they struggle, ask: ''What words tell us what color it is? Or how loud it is?''', 'How do those words help make the poem interesting?', '{"default":{"theme":"the wind"},"ug":{"theme":"the rain on a tin roof"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L4_A', 'ENG_RC2j', 4, 'A', 'Writing an Acrostic Poem', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Write your name downwards on the paper. Now write a describing word or short phrase that starts with each letter of your name. This is an acrostic poem!', 'Child successfully formats and writes an acrostic poem based on their name.', 'If they struggle to find words, help them brainstorm traits or things they like.', 'Does an acrostic poem have to rhyme? (No).', '{"default":{"format":"acrostic"},"ug":{"format":"acrostic"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L4_B', 'ENG_RC2j', 4, 'B', 'Converting Prose to Poetry', 'A printed prose sentence, Paper, Pencil', NULL, NULL, NULL, NULL, 'Here is a normal sentence: ''The big green frog jumped into the cold water with a splash.'' Turn this into a short poem by chopping it into lines and maybe adding a rhyme.', 'Child restructures the prose into a poetic format (e.g., adding line breaks, altering words).', 'If they just copy it, show them how to break it: ''The big green frog / jumped off the log...''', 'How does your poem look and sound different from the normal sentence?', '{"default":{"theme":"frog in water"},"ug":{"theme":"frog in water"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L4_C', 'ENG_RC2j', 4, 'C', 'Reciting from Memory', 'A short poem practiced previously', NULL, NULL, NULL, NULL, 'You have been practicing this short poem. Put the paper away and recite it from memory. Try to use expression and rhythm!', 'Child recites the poem accurately with appropriate prosody.', 'If they forget, prompt them with the first word of the line.', 'Is it easier to memorize a poem or a normal story paragraph? Why?', '{"default":{"task":"memorization"},"ug":{"task":"memorization"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('ENG_RC2j_L4_M', 'ENG_RC2j', 4, 'M', 'Creating a Choral Chant', 'Paper, Pencil', NULL, NULL, NULL, NULL, 'Think of a chore we do at home (like sweeping or washing dishes). Create a short, two-line rhythmic chant we could say while doing that chore to make it fun. Teach it to me.', 'Child creates a rhythmic, functional chant and demonstrates it with steady beat.', 'Do not correct during the task. The goal is applying rhythm to language creatively.', 'Does your chant match the rhythm of the work we are doing?', '{"default":{"chore":"sweeping"},"ug":{"chore":"sweeping or washing plates"}}', 0);

