INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_SE2a_L3_C', 'SCI_SE2a', 3, 'C', 'Discern (Anomaly Detection)', NULL, 'Ugandan fruit (e.g., jackfruit), leaves, stone', 'any local fruit, grass, wood', 'Risk_Level_A', 'Safe for independent work. Do not eat unknown plants.', 'Variation C: "Look at this flawed setup for Sensory Observation. Spot the error and explain how to fix it."', 'Child identifies the mechanical error and explains how Sensory Observation really works.', 'Child agrees with the flawed reasoning. Parent prompts them to think about physical variables.', 'What was the mechanical error?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);
