INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_ES2b_L3_A', 'SCI_ES2b', 3, 'A', 'Discern (Anomaly Detection)', NULL, '2 types of soil (sand/clay), water, 2 clear cups', 'cut plastic bottles, mud', 'Risk_Level_A', 'Wash hands after handling soil.', 'Variation A: "Show me how Soil & Water (Agriculture) works physically. If I do [X], what should happen according to the rules of science?"', 'Child identifies the mechanical error and explains how Soil & Water (Agriculture) really works.', 'Child agrees with the flawed reasoning. Parent prompts them to think about physical variables.', 'What was the mechanical error?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland","shamba"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('SCI_ES2b_L3_B', 'SCI_ES2b', 3, 'B', 'Discern (Anomaly Detection)', NULL, '2 types of soil (sand/clay), water, 2 clear cups', 'cut plastic bottles, mud', 'Risk_Level_A', 'Wash hands after handling soil.', 'Variation B: "Amara tried to do an experiment on Soil & Water (Agriculture) but it failed. Why did she fail physically?"', 'Child identifies the mechanical error and explains how Soil & Water (Agriculture) really works.', 'Child agrees with the flawed reasoning. Parent prompts them to think about physical variables.', 'What was the mechanical error?', '{"default":{"names":["Alex","Sam","Pat"],"settings":["park","school","store"],"food":["apples","bread","milk"]},"ug":{"names":["Amara","Tendo","Azie"],"settings":["Kampala market","village","garden","savanna","wetland","shamba"],"food":["matooke","mangoes","chapati","jackfruit"]}}', 0);
